  div.innerHTML = `<span class="t-ts">${evt.ts}</span> <span class="t-lvl ${evt.lvl}">[${evt.lvl.padEnd(4)}]</span> <span class="t-ctx">${evt.ctx}</span> <span class="t-msg">${evt.msg}</span>`;
