let lineIndex = 0;
function addTraceLine() {
  const evt = traceEvents[lineIndex % traceEvents.length];
  const div = document.createElement('div');
  div.className = 'trace-line';
  div.innerHTML = `<span class="t-ts">${evt.ts}</span> <span class="t-lvl ${evt.lvl}">[${evt.lvl.padEnd(4)}]</span> <span class="t-ctx">${evt.ctx}</span> <span class="t-msg">${evt.msg}</span>`;
  termBody.appendChild(div);

  // Keep only last ~12 lines visible
  while (termBody.children.length > 12) {
    termBody.removeChild(termBody.firstChild);
  }
  termBody.scrollTop = termBody.scrollHeight;
  lineIndex++;
}

