</aside>

<!-- ═══════════ MAIN ═══════════ -->
<div class="main" id="main">
  <!-- Top Bar -->
  <header class="topbar">
    <div class="topbar-title">Operations Overview</div>
    <div class="topbar-spacer"></div>
    <div class="env-switcher">
      <button class="env-btn" onclick="setEnv(this)">Dev</button>
      <button class="env-btn" onclick="setEnv(this)">Staging</button>
      <button class="env-btn active" onclick="setEnv(this)">Prod</button>
    </div>
    <div class="date-picker-group">
      <label>From</label>
