      <label>To</label>
      <input type="date" class="date-input" id="dateTo" value="">
    </div>
    <div class="topbar-avatar" title="Admin User">AU</div>
  </header>

  <div class="content">
    <!-- KPI Strip -->
    <div class="kpi-strip" id="kpiStrip"></div>

    <!-- Chart -->
    <div class="chart-card">
      <div class="chart-header">
        <div>
          <div class="chart-title">Latency & Error Rate — 24h Window</div>
          <div style="font-size:13px;color:var(--text-secondary);margin-top:2px;">Last updated 12s ago</div>
        </div>
        <div class="chart-legend">
          <div class="legend-item"><span class="legend-dot" style="background:var(--emerald)"></span> P50 Latency</div>
          <div class="legend-item"><span class="legend-dot" style="background:var(--warning)"></span> P99 Latency</div>
          <div class="legend-item"><span class="legend-dot" style="background:var(--danger)"></span> Error Rate</div>
        </div>
      </div>
      <div class="chart-container" id="chartContainer">
        <div class="chart-tooltip" id="chartTooltip"></div>
