      <div class="table-wrap">
        <table id="serviceTable">
          <thead>
            <tr>
              <th data-col="name" onclick="sortTable(this)">Service <span class="sort-icon">▲▼</span></th>
              <th data-col="status" onclick="sortTable(this)">Status <span class="sort-icon">▲▼</span></th>
              <th data-col="p99" onclick="sortTable(this)">P99 Latency <span class="sort-icon">▲▼</span></th>
              <th data-col="errorRate" onclick="sortTable(this)">Error Rate <span class="sort-icon">▲▼</span></th>
              <th data-col="deploy" onclick="sortTable(this)">Last Deploy <span class="sort-icon">▲▼</span></th>
            </tr>
