<script>
// ═══════════════════════════════════════
// DATA
// ═══════════════════════════════════════

const services = [
  { name: "api-gateway",    status: "healthy",  p99: 142,  errorRate: 0.12, deploy: "2024-01-15 08:30" },
  { name: "auth-service",   status: "healthy",  p99: 89,   errorRate: 0.05, deploy: "2024-01-15 07:15" },
  { name: "user-service",   status: "healthy",  p99: 67,   errorRate: 0.03, deploy: "2024-01-14 22:00" },
  { name: "payment-svc",    status: "degraded", p99: 312,  errorRate: 1.87, deploy: "2024-01-15 06:45" },
  { name: "order-service",  status: "healthy",  p99: 156,  errorRate: 0.21, deploy: "2024-01-15 09:00" },
  { name: "inventory-svc",  status: "healthy",  p99: 95,   errorRate: 0.08, deploy: "2024-01-14 18:30" },
  { name: "notification",   status: "healthy",  p99: 43,   errorRate: 0.02, deploy: "2024-01-15 05:20" },
  { name: "search-service", status: "healthy",  p99: 178,  errorRate: 0.34, deploy: "2024-01-15 03:10" },
  { name: "recommendation", status: "degraded", p99: 267,  errorRate: 1.23, deploy: "2024-01-14 20:00" },
  { name: "analytics-svc",  status: "healthy",  p99: 201,  errorRate: 0.15, deploy: "2024-01-15 02:30" },
  { name: "cache-layer",    status: "healthy",  p99: 12,   errorRate: 0.01, deploy: "2024-01-15 01:00" },
  { name: "ml-pipeline",    status: "critical", p99: 890,  errorRate: 5.67, deploy: "2024-01-14 16:45" },
];

// Generate 48 data points (30-min intervals for 24h)
function generateTimeSeries(n, base, variance, trend) {
  const data = [];
  for (let i = 0; i < n; i++) {
    const t = i / n;
    const spike = Math.exp(-Math.pow((t - 0.65) * 8, 2)) * variance * 2;
    const val = base + Math.sin(t * Math.PI * 3 + i) * variance * 0.4
                + (Math.random() - 0.5) * variance * 0.6 + spike + trend * t;
    data.push(Math.max(0, val));
  }
  return data;
}

const dataPoints = 48;
const p50Data = generateTimeSeries(dataPoints, 45, 15, 5);
const p99Data = generateTimeSeries(dataPoints, 180, 60, 10);
const errorData = generateTimeSeries(dataPoints, 0.5, 0.4, 0.3);
const inflightData = generateTimeSeries(dataPoints, 340, 80, 20);

const hours = [];
const now = new Date();
for (let i = dataPoints - 1; i >= 0; i--) {
  const d = new Date(now - i * 30 * 60000);
  hours.push(d);
}

// ═══════════════════════════════════════
// SIDEBAR
// ═══════════════════════════════════════

function toggleSidebar() {
  const sb = document.getElementById('sidebar');
  const mn = document.getElementById('main');
  const icon = document.getElementById('collapseIcon');
  sb.classList.toggle('collapsed');
  mn.classList.toggle('shifted');
  if (sb.classList.contains('collapsed')) {
    icon.innerHTML = '<polyline points="13,17 18,12 13,7"/><polyline points="6,17 11,12 6,7"/>';
  } else {
    icon.innerHTML = '<polyline points="11,17 6,12 11,7"/><polyline points="18,17 13,12 18,7"/>';
  }
}

function setActiveNav(el) {
  document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
  el.classList.add('active');
}

// ═══════════════════════════════════════
// ENV SWITCHER
// ═══════════════════════════════════════

function setEnv(btn) {
  document.querySelectorAll('.env-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
}

// ═══════════════════════════════════════
// DATE DEFAULTS
// ═══════════════════════════════════════

(function initDates() {
  const today = new Date();
  const yesterday = new Date(today - 86400000);
  document.getElementById('dateTo').value = today.toISOString().split('T')[0];
  document.getElementById('dateFrom').value = yesterday.toISOString().split('T')[0];
})();

// ═══════════════════════════════════════
// KPI CARDS
// ═══════════════════════════════════════

function buildSparklineSVG(data, color, w, h) {
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const pad = 2;
  const points = data.map((v, i) => {
    const x = pad + (i / (data.length - 1)) * (w - pad * 2);
    const y = h - pad - ((v - min) / range) * (h - pad * 2);
    return `${x},${y}`;
  });
  const linePath = points.join(' ');
  const areaPath = linePath + ` L${w - pad},${h - pad} L${pad},${h - pad} Z`;

  return `<svg viewBox="0 0 ${w} ${h}" xmlns="http://www.w3.org/2000/svg">
    <defs>
      <linearGradient id="sg_${color.replace('#','')}" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="${color}" stop-opacity="0.25"/>
        <stop offset="100%" stop-color="${color}" stop-opacity="0.02"/>
      </linearGradient>
    </defs>
    <polygon points="${areaPath}" fill="url(#sg_${color.replace('#','')})"/>
    <polyline points="${linePath}" fill="none" stroke="${color}" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>
    <circle cx="${points[points.length-1].split(',')[0]}" cy="${points[points.length-1].split(',')[1]}" r="3" fill="${color}" stroke="#fff" stroke-width="1.5"/>
  </svg>`;
}

function renderKPIs() {
  const kpis = [
    { label: 'P50 Latency', value: p50Data[p50Data.length-1].toFixed(1), unit: 'ms', sparkData: p50Data, color: 'var(--emerald)', delta: '+3.2%', dir: 'up' },
    { label: 'P99 Latency', value: p99Data[p99Data.length-1].toFixed(0), unit: 'ms', sparkData: p99Data, color: 'var(--warning)', delta: '+12.5%', dir: 'up' },
    { label: 'Error Rate', value: errorData[errorData.length-1].toFixed(2), unit: '%', sparkData: errorData, color: 'var(--danger)', delta: '-0.4%', dir: 'down' },
    { label: 'In-Flight', value: Math.round(inflightData[inflightData.length-1]).toLocaleString(), unit: ' reqs', sparkData: inflightData, color: 'var(--info)', delta: '+8.1%', dir: 'up' },
  ];

  const strip = document.getElementById('kpiStrip');
  strip.innerHTML = kpis.map(k => `
    <div class="kpi-card">
      <div class="kpi-label">${k.label}</div>
      <div class="kpi-value">${k.value}<span class="unit">${k.unit}</span></div>
      <div class="kpi-sub ${k.dir}">
        ${k.dir === 'up' ? '▲' : '▼'} ${k.delta} vs last hour
      </div>
      <div class="kpi-sparkline">${buildSparklineSVG(k.sparkData, k.color, 260, 40)}</div>
    </div>
  `).join('');
}

// ═══════════════════════════════════════
// MAIN CHART
// ═══════════════════════════════════════

function renderChart() {
  const container = document.getElementById('chartContainer');
  const W = 1200, H = 360;
  const pad = { top: 20, right: 70, bottom: 40, left: 60 };
  const cw = W - pad.left - pad.right;
  const ch = H - pad.top - pad.bottom;

  const p50Max = Math.max(...p50Data);
  const p99Max = Math.max(...p99Data);
  const leftMax = Math.ceil((Math.max(p50Max, p99Max)) / 50) * 50;
  const errMax = Math.ceil(Math.max(...errorData) / 0.5) * 0.5;

  function xScale(i) { return pad.left + (i / (dataPoints - 1)) * cw; }
  function yScaleLeft(v) { return pad.top + ch - (v / leftMax) * ch; }
  function yScaleRight(v) { return pad.top + ch - (v / errMax) * ch; }

  function makePath(data, yScale) {
    return data.map((v, i) => `${i === 0 ? 'M' : 'L'}${xScale(i).toFixed(1)},${yScale(v).toFixed(1)}`).join(' ');
  }

  const p50Path = makePath(p50Data, yScaleLeft);
  const p99Path = makePath(p99Data, yScaleLeft);
  const errPath = makePath(errorData, yScaleRight);

  // Gridlines
  const yTicksLeft = 5;
  let gridHTML = '';
  for (let i = 0; i <= yTicksLeft; i++) {
    const val = (leftMax / yTicksLeft) * i;
    const y = yScaleLeft(val);
    gridHTML += `<line x1="${pad.left}" y1="${y}" x2="${W - pad.right}" y2="${y}" stroke="#e2e8f0" stroke-width="1"/>`;
    gridHTML += `<text x="${pad.left - 10}" y="${y + 4}" text-anchor="end" fill="#94a3b8" font-size="11" font-family="inherit">${val}</text>`;
  }
  // Right axis
  for (let i = 0; i <= 4; i++) {
    const val = (errMax / 4) * i;
    const y = yScaleRight(val);
    gridHTML += `<text x="${W - pad.right + 10}" y="${y + 4}" text-anchor="start" fill="#94a3b8" font-size="11" font-family="inherit">${val.toFixed(1)}%</text>`;
  }

  // X-axis labels (every 6th point = ~3h)
  let xLabels = '';
  for (let i = 0; i < dataPoints; i += 6) {
    const x = xScale(i);
    const h = hours[i].getHours();
    const label = h % 3 === 0 ? `${h.toString().padStart(2,'0')}:00` : '';
    xLabels += `<line x1="${x}" y1="${pad.top + ch}" x2="${x}" y2="${pad.top + ch + 5}" stroke="#cbd5e1" stroke-width="1"/>`;
    xLabels += `<text x="${x}" y="${H - 8}" text-anchor="middle" fill="#94a3b8" font-size="11" font-family="inherit">${label}</text>`;
  }

  // Axis labels
  const axisLabelLeft = `<text x="14" y="${pad.top + ch/2}" text-anchor="middle" fill="#64748b" font-size="12" font-family="inherit" transform="rotate(-90,14,${pad.top + ch/2})">Latency (ms)</text>`;
  const axisLabelRight = `<text x="${W - 4}" y="${pad.top + ch/2}" text-anchor="middle" fill="#64748b" font-size="12" font-family="inherit" transform="rotate(90,${W - 4},${pad.top + ch/2})">Error Rate (%)</text>`;

  // Invisible hit areas for hover
  let hitAreas = '';
  for (let i = 0; i < dataPoints; i++) {
    hitAreas += `<rect class="chart-hit" data-index="${i}" x="${xScale(i) - cw/dataPoints/2}" y="${pad.top}" width="${cw/dataPoints}" height="${ch}" fill="transparent" cursor="crosshair"/>`;
  }

  // Vertical guide line (hidden by default)
  const guideLine = `<line id="chartGuide" x1="0" y1="${pad.top}" x2="0" y2="${pad.top+ch}" stroke="#94a3b8" stroke-width="1" stroke-dasharray="4,3" opacity="0"/>`;
  const guideDots = [
    `<circle id="guideDot0" cx="0" cy="0" r="4" fill="#059669" stroke="#fff" stroke-width="2" opacity="0"/>`,
    `<circle id="guideDot1" cx="0" cy="0" r="4" fill="#f59e0b" stroke="#fff" stroke-width="2" opacity="0"/>`,
    `<circle id="guideDot2" cx="0" cy="0" r="4" fill="#ef4444" stroke="#fff" stroke-width="2" opacity="0"/>`,
  ].join('');

  const svg = `<svg viewBox="0 0 ${W} ${H}" xmlns="http://www.w3.org/2000/svg" id="mainChart">
    ${gridHTML}
    ${xLabels}
    ${axisLabelLeft}
    ${axisLabelRight}
    <path d="${p50Path}" fill="none" stroke="#059669" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    <path d="${p99Path}" fill="none" stroke="#f59e0b" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    <path d="${errPath}" fill="none" stroke="#ef4444" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
    ${guideLine}
    ${guideDots}
    ${hitAreas}
  </svg>`;

  // Insert before tooltip
  const existing = container.querySelector('svg');
  if (existing) existing.remove();
  container.insertAdjacentHTML('afterbegin', svg);

  // Hover logic
  const tooltip = document.getElementById('chartTooltip');
  const guide = document.getElementById('chartGuide');
  const dots = [document.getElementById('guideDot0'), document.getElementById('guideDot1'), document.getElementById('guideDot2')];

  container.querySelectorAll('.chart-hit').forEach(hit => {
    hit.addEventListener('mouseenter', function() {
      const i = parseInt(this.dataset.index);
      const x = xScale(i);
      guide.setAttribute('x1', x);
      guide.setAttribute('x2', x);
      guide.setAttribute('opacity', '1');

      const cy0 = yScaleLeft(p50Data[i]);
      const cy1 = yScaleLeft(p99Data[i]);
      const cy2 = yScaleRight(errorData[i]);

      dots[0].setAttribute('cx', x); dots[0].setAttribute('cy', cy0); dots[0].setAttribute('opacity', '1');
      dots[1].setAttribute('cx', x); dots[1].setAttribute('cy', cy1); dots[1].setAttribute('opacity', '1');
      dots[2].setAttribute('cx', x); dots[2].setAttribute('cy', cy2); dots[2].setAttribute('opacity', '1');

      const timeStr = hours[i].toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
      tooltip.innerHTML = `
        <div class="tt-label">${timeStr}</div>
        <div class="tt-row"><span class="tt-dot" style="background:#059669"></span> P50: ${p50Data[i].toFixed(1)} ms</div>
        <div class="tt-row"><span class="tt-dot" style="background:#f59e0b"></span> P99: ${p99Data[i].toFixed(0)} ms</div>
        <div class="tt-row"><span class="tt-dot" style="background:#ef4444"></span> Error: ${errorData[i].toFixed(2)}%</div>
      `;
      tooltip.classList.add('visible');

      const svgRect = document.getElementById('mainChart').getBoundingClientRect();
      const contRect = container.getBoundingClientRect();
      const relX = svgRect.left - contRect.left + (x / W) * svgRect.width;
      const relY = svgRect.top - contRect.top + (cy0 / H) * svgRect.height;
      tooltip.style.left = (relX + 16) + 'px';
      tooltip.style.top = (relY - 20) + 'px';
    });

    hit.addEventListener('mouseleave', function() {
      guide.setAttribute('opacity', '0');
      dots.forEach(d => d.setAttribute('opacity', '0'));
      tooltip.classList.remove('visible');
    });
  });
}

// ═══════════════════════════════════════
// SERVICE TABLE
// ═══════════════════════════════════════

let sortCol = null;
let sortDir = 'asc';

const statusOrder = { critical: 0, degraded: 1, healthy: 2 };

function renderTable(data) {
  const tbody = document.getElementById('tableBody');
  const maxP99 = Math.max(...services.map(s => s.p99));

  tbody.innerHTML = data.map(s => {
    const barPct = Math.min(100, (s.p99 / maxP99) * 100);
    const barColor = s.p99 > 500 ? 'var(--danger)' : s.p99 > 200 ? 'var(--warning)' : 'var(--emerald)';
    const dotColor = s.status === 'healthy' ? 'var(--emerald)' : s.status === 'degraded' ? 'var(--warning)' : 'var(--danger)';

    return `<tr>
      <td class="service-name"><span class="service-dot" style="background:${dotColor}"></span>${s.name}</td>
      <td><span class="status-pill ${s.status}"><span class="pill-dot"></span>${s.status.charAt(0).toUpperCase() + s.status.slice(1)}</span></td>
      <td>
        <div class="latency-bar-wrap">
          <span class="latency-val">${s.p99} ms</span>
          <div class="latency-bar"><div class="latency-bar-fill" style="width:${barPct}%;background:${barColor}"></div></div>
        </div>
      </td>
      <td class="error-val" style="color:${s.errorRate > 1 ? 'var(--danger)' : s.errorRate > 0.5 ? 'var(--warning)' : 'inherit'}">${s.errorRate.toFixed(2)}%</td>
      <td class="deploy-val">${s.deploy}</td>
    </tr>`;
  }).join('');
}

function sortTable(th) {
  const col = th.dataset.col;
  if (sortCol === col) {
    sortDir = sortDir === 'asc' ? 'desc' : 'asc';
  } else {
    sortCol = col;
    sortDir = 'asc';
  }

  // Update header classes
  document.querySelectorAll('#serviceTable thead th').forEach(h => {
    h.classList.remove('sorted-asc', 'sorted-desc');
    h.querySelector('.sort-icon').textContent = '▲▼';
  });
  th.classList.add(sortDir === 'asc' ? 'sorted-asc' : 'sorted-desc');
  th.querySelector('.sort-icon').textContent = sortDir === 'asc' ? '▲' : '▼';

  const sorted = [...services].sort((a, b) => {
    let va, vb;
    switch (col) {
      case 'name': va = a.name; vb = b.name; break;
      case 'status': va = statusOrder[a.status]; vb = statusOrder[b.status]; break;
      case 'p99': va = a.p99; vb = b.p99; break;
      case 'errorRate': va = a.errorRate; vb = b.errorRate; break;
      case 'deploy': va = a.deploy; vb = b.deploy; break;
    }
    if (typeof va === 'string') return sortDir === 'asc' ? va.localeCompare(vb) : vb.localeCompare(va);
    return sortDir === 'asc' ? va - vb : vb - va;
  });

  renderTable(sorted);
}

// ═══════════════════════════════════════
// INIT
// ═══════════════════════════════════════

renderKPIs();
renderChart();
renderTable(services);
</script>
</body>
</html>
