<script>
// ═══════════════════════════════════════
// DATA
// ═══════════════════════════════════════

const services = [
  { name: "api-gateway",    status: "healthy",  p99: 142,  errorRate: 0.12, deploy: "2024-01-15 08:30" },
  { name: "auth-service",   status: "healthy",  p99: 89,   errorRate: 0.05, deploy: "2024-01-15 07:15" },
  { name: "user-service",   status: "healthy",  p99: 67,   errorRate: 0.03, deploy: "2024-01-14 22:00" },
  { name: "payment-svc",    status: "degraded", p99: 312,  errorRate: 1.87, deploy: "2024-01-15 06:45" },
  { name: "order-service",  status: "healthy",  p99: 156,  errorRate: 0.21, deploy: "2024-01-15 09:00" },
  { name: "inventory-svc",  status: "healthy",  p99: 95,   errorRate: 0.08, deploy: "2024-01-14 18:30" },
  { name: "notification",   status: "healthy",  p99: 43,   errorRate: 0.02, deploy: "2024-01-15 05:20" },
  { name: "search-service", status: "healthy",  p99: 178,  errorRate: 0.34, deploy: "2024-01-15 03:10" },
  { name: "recommendation", status: "degraded", p99: 267,  errorRate: 1.23, deploy: "2024-01-14 20:00" },
  { name: "analytics-svc",  status: "healthy",  p99: 201,  errorRate: 0.15, deploy: "2024-01-15 02:30" },
  { name: "cache-layer",    status: "healthy",  p99: 12,   errorRate: 0.01, deploy: "2024-01-15 01:00" },
  { name: "ml-pipeline",    status: "critical", p99: 890,  errorRate: 5.67, deploy: "2024-01-14 16:45" },
];

// Generate 48 data points (30-min intervals for 24h)
function generateTimeSeries(n, base, variance, trend) {
  const data = [];
  for (let i = 0; i < n; i++) {
    const t = i / n;
    const spike = Math.exp(-Math.pow((t - 0.65) * 8, 2)) * variance * 2;
    const val = base + Math.sin(t * Math.PI * 3 + i) * variance * 0.4
                + (Math.random() - 0.5) * variance * 0.6 + spike + trend * t;
    data.push(Math.max(0, val));
  }
  return data;
}

const dataPoints = 48;
const p50Data = generateTimeSeries(dataPoints, 45, 15, 5);
const p99Data = generateTimeSeries(dataPoints, 180, 60, 10);
const errorData = generateTimeSeries(dataPoints, 0.5, 0.4, 0.3);
const inflightData = generateTimeSeries(dataPoints, 340, 80, 20);

const hours = [];
const now = new Date();
for (let i = dataPoints - 1; i >= 0; i--) {
  const d = new Date(now - i * 30 * 60000);
  hours.push(d);
}

// ═══════════════════════════════════════
// SIDEBAR
