<script>
// Scroll reveal
const reveals = document.querySelectorAll('.reveal');
const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
    }
  });
}, { threshold: 0.15, rootMargin: '0px 0px -40px 0px' });

reveals.forEach(el => observer.observe(el));

// Ambient glow follows cursor
const glow = document.getElementById('glow');
let mouseX = 0, mouseY = 0, glowX = 0, glowY = 0;

document.addEventListener('mousemove', (e) => {
  mouseX = e.clientX - 200;
  mouseY = e.clientY - 200;
});

function animateGlow() {
  glowX += (mouseX - glowX) * 0.05;
  glowY += (mouseY - glowY) * 0.05;
  glow.style.transform = `translate(${glowX}px, ${glowY}px)`;
  requestAnimationFrame(animateGlow);
}
animateGlow();

// Word swap timing fix - recalculate on load
document.addEventListener('DOMContentLoaded', () => {
  const words = document.querySelectorAll('.word-swap .word');
  const cycleDuration = 9000;
  const showDuration = 2800;

  words.forEach((word, i) => {
    word.style.animation = 'none';
    word.style.opacity = '0';
    word.style.transform = 'translateY(30px) rotateX(40deg)';
    word.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
  });

  let currentIndex = 0;

  function showWord(index) {
    words.forEach((word, i) => {
      if (i === index) {
        word.style.opacity = '1';
        word.style.transform = 'translateY(0) rotateX(0)';
      } else {
        word.style.opacity = '0';
        word.style.transform = i < index 
          ? 'translateY(-20px) rotateX(-20deg)' 
          : 'translateY(30px) rotateX(40deg)';
      }
    });
  }

  showWord(0);

  setInterval(() => {
    currentIndex = (currentIndex + 1) % words.length;
    showWord(currentIndex);
  }, cycleDuration);
});
</script>

