  100% { left: 100%; }
}

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
}

/* ── Divider ── */
.divider {
  width: 100%;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 3rem;
}

.divider hr {
  border: none;
  height: 1px;
  background: var(--text-dim);
  opacity: 0.2;
}

/* ── WORK SECTION ── */
.work {
  padding-top: 8rem;
  padding-bottom: 8rem;
}

.section-label {
  font-family: var(--mono);
  font-size: 0.7rem;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-dim);
  margin-bottom: 4rem;
  display: flex;
  align-items: center;
  gap: 1rem;
}

.section-label::before {
  content: '';
  width: 20px;
  height: 1px;
  background: var(--accent);
}

.work-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 1.5rem;
}

.work-card {
  background: var(--bg-card);
  border: 1px solid #ffffff08;
  border-radius: 4px;
  overflow: hidden;
  transition: border-color 0.4s ease, transform 0.4s ease;
  cursor: pointer;
}

.work-card:hover {
  border-color: #ffffff15;
  transform: translateY(-2px);
}

.card-thumbnail {
  width: 100%;
  aspect-ratio: 16/10;
  position: relative;
  overflow: hidden;
}

/* Card 1: Circular composition */
.card-1 .card-thumbnail {
  background: linear-gradient(135deg, #1a1a22 0%, #0d0d12 100%);
}

.card-1 .card-thumbnail::before {
  content: '';
  position: absolute;
  width: 60%;
  height: 60%;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, var(--accent), #8a3a1a);
  top: 20%;
  left: 25%;
  opacity: 0.8;
  mix-blend-mode: screen;
}

.card-1 .card-thumbnail::after {
  content: '';
  position: absolute;
  width: 40%;
  height: 40%;
  border-radius: 50%;
  border: 1px solid rgba(212, 132, 90, 0.3);
  top: 30%;
  left: 35%;
}

.card-1 .card-thumbnail .shape-extra {
  position: absolute;
  width: 25%;
  height: 25%;
  background: linear-gradient(135deg, transparent 40%, rgba(212, 132, 90, 0.15));
  border-radius: 50%;
  bottom: 15%;
  right: 20%;
}

/* Card 2: Geometric grid */
.card-2 .card-thumbnail {
  background: linear-gradient(180deg, #14141a 0%, #1a1520 100%);
}

.card-2 .card-thumbnail::before {
  content: '';
  position: absolute;
  inset: 15%;
  border: 1px solid rgba(212, 132, 90, 0.2);
}

.card-2 .card-thumbnail::after {
  content: '';
  position: absolute;
  top: 25%;
  left: 25%;
  width: 50%;
  height: 50%;
  background: linear-gradient(135deg, rgba(212, 132, 90, 0.25), rgba(212, 132, 90, 0.05));
  transform: rotate(12deg);
}

.card-2 .card-thumbnail .shape-extra {
  position: absolute;
  width: 3px;
  height: 40%;
  background: linear-gradient(to bottom, var(--accent), transparent);
  top: 30%;
  left: 50%;
  opacity: 0.4;
}

.card-2 .card-thumbnail .shape-extra2 {
  position: absolute;
  width: 40%;
  height: 3px;
  background: linear-gradient(to right, transparent, var(--accent));
  top: 50%;
  right: 10%;
  opacity: 0.3;
}

/* Card 3: Layered rectangles */
.card-3 .card-thumbnail {
  background: linear-gradient(160deg, #151518 0%, #101015 100%);
}

.card-3 .card-thumbnail::before {
  content: '';
  position: absolute;
