  top: 20%;
  left: 15%;
  border-radius: 2px;
}

.card-3 .card-thumbnail::after {
  content: '';
  position: absolute;
  width: 35%;
  height: 45%;
  background: linear-gradient(225deg, rgba(212, 132, 90, 0.4), rgba(180, 90, 50, 0.1));
