<title>Conduit — Pricing</title>
<style>
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --bg-primary:#0a0a0f;
    --bg-secondary:#12121a;
    --bg-card:#16161f;
    --bg-card-hover:#1a1a25;
    --border-subtle:#2a2a3a;
    --border-indigo:#4f46e5;
    --text-primary:#f0f0f5;
    --text-secondary:#9898a8;
    --text-muted:#6a6a7a;
    --accent:#6366f1;
    --accent-light:#818cf8;
    --accent-glow:rgba(99,102,241,.25);
    --green:#22c55e;
    --radius:12px;
    --radius-lg:16px;
    --transition:0.3s cubic-bezier(.4,0,.2,1);
  }
  html{scroll-behavior:smooth}
  body{
    font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,'Helvetica Neue',Arial,sans-serif;
    background:var(--bg-primary);
    color:var(--text-primary);
    line-height:1.6;
    min-height:100vh;
    overflow-x:hidden;
  }

  /* ── Header ── */
  header{
    position:sticky;top:0;z-index:100;
    background:rgba(10,10,15,.85);
    backdrop-filter:blur(16px);
    border-bottom:1px solid var(--border-subtle);
  }
  .header-inner{
    max-width:1200px;margin:0 auto;padding:0 24px;
    display:flex;align-items:center;justify-content:space-between;
    height:64px;
  }
  .logo{
    font-size:1.35rem;font-weight:700;letter-spacing:-.5px;
    background:linear-gradient(135deg,var(--accent-light),#a78bfa);
    -webkit-background-clip:text;-webkit-text-fill-color:transparent;
    display:flex;align-items:center;gap:8px;
  }
  .logo svg{flex-shrink:0}
  nav{display:flex;align-items:center;gap:32px}
  nav a{
    color:var(--text-secondary);text-decoration:none;font-size:.9rem;
    transition:color var(--transition);
  }
  nav a:hover{color:var(--text-primary)}
  .status-pill{
    display:inline-flex;align-items:center;gap:6px;
    background:rgba(34,197,94,.1);border:1px solid rgba(34,197,94,.25);
    padding:4px 12px;border-radius:20px;font-size:.78rem;color:var(--green);
  }
  .status-dot{
    width:6px;height:6px;border-radius:50%;background:var(--green);
    animation:pulse-dot 2s ease-in-out infinite;
  }
  @keyframes pulse-dot{0%,100%{opacity:1}50%{opacity:.4}}

  /* ── Hero ── */
  .hero{
    text-align:center;padding:80px 24px 40px;
    max-width:700px;margin:0 auto;
  }
  .hero h1{
    font-size:clamp(2rem,5vw,3.2rem);font-weight:800;
    letter-spacing:-.03em;line-height:1.15;margin-bottom:16px;
  }
  .hero h1 span{
    background:linear-gradient(135deg,var(--accent-light),#c084fc);
    -webkit-background-clip:text;-webkit-text-fill-color:transparent;
  }
  .hero p{color:var(--text-secondary);font-size:1.1rem;max-width:520px;margin:0 auto}

  /* ── Toggle ── */
  .toggle-wrap{
    display:flex;align-items:center;justify-content:center;gap:16px;
    margin:40px 0 48px;
  }
  .toggle-label{
    font-size:.95rem;color:var(--text-secondary);
    transition:color var(--transition);cursor:pointer;
  }
  .toggle-label.active{color:var(--text-primary);font-weight:600}
  .toggle-track{
    width:52px;height:28px;border-radius:14px;
    background:var(--border-subtle);cursor:pointer;
    position:relative;transition:background var(--transition);
    border:2px solid transparent;
  }
  .toggle-track:hover{border-color:var(--accent)}
  .toggle-track.annual{background:var(--accent)}
  .toggle-thumb{
    position:absolute;top:2px;left:2px;
    width:20px;height:20px;border-radius:50%;
    background:#fff;
    transition:transform var(--transition);
    box-shadow:0 1px 4px rgba(0,0,0,.3);
  }
  .toggle-track.annual .toggle-thumb{transform:translateX(24px)}
  .save-badge{
    background:linear-gradient(135deg,#22c55e,#16a34a);
    color:#fff;font-size:.72rem;font-weight:700;
    padding:3px 10px;border-radius:20px;
    letter-spacing:.5px;text-transform:uppercase;
  }

  /* ── Pricing Grid ── */
  .pricing-grid{
    display:grid;
    grid-template-columns:repeat(3,1fr);
    gap:24px;max-width:1100px;margin:0 auto;
    padding:0 24px 80px;
    align-items:start;
  }
  .tier-card{
    background:var(--bg-card);
    border:1px solid var(--border-subtle);
    border-radius:var(--radius-lg);
    padding:36px 28px 32px;
    position:relative;
    transition:transform var(--transition),box-shadow var(--transition),border-color var(--transition);
  }
  .tier-card:hover{
    transform:translateY(-4px);
    box-shadow:0 20px 60px rgba(0,0,0,.3);
  }
  .tier-card.popular{
    border-color:transparent;
    padding:36px 28px 32px;
    z-index:2;
  }
  .popular-card-wrap{
    position:relative;
    border-radius:var(--radius-lg);
    padding:2px;
    background:conic-gradient(from 0deg,#6366f1,#a78bfa,#6366f1,#818cf8,#6366f1);
    animation:spin-border 3s linear infinite;
  }
  @keyframes spin-border{to{background:conic-gradient(from 360deg,#6366f1,#a78bfa,#6363f1,#818cf8,#6366f1)}}
  .popular-card-wrap .tier-card{
    background:var(--bg-card);
    border:none;
    border-radius:calc(var(--radius-lg) - 2px);
  }
  .popular-tag{
    position:absolute;top:-13px;left:50%;transform:translateX(-50%);
    background:linear-gradient(135deg,var(--accent),#a78bfa);
    color:#fff;font-size:.72rem;font-weight:700;
    padding:4px 16px;border-radius:20px;
    letter-spacing:.5px;text-transform:uppercase;
    white-space:nowrap;z-index:3;
  }
  .tier-name{
    font-size:.85rem;text-transform:uppercase;letter-spacing:1.5px;
    color:var(--text-muted);font-weight:600;margin-bottom:8px;
  }
  .tier-tagline{
    font-size:.92rem;color:var(--text-secondary);margin-bottom:20px;
    line-height:1.5;
  }
  .price-row{display:flex;align-items:baseline;gap:4px;margin-bottom:4px}
  .currency{font-size:1.4rem;font-weight:600;color:var(--text-secondary)}
  .price-value{
    font-size:3.2rem;font-weight:800;letter-spacing:-.03em;
    transition:opacity .25s ease;
    min-width:60px;display:inline-block;
  }
  .price-value.animating{opacity:0}
  .price-period{font-size:.9rem;color:var(--text-muted)}
  .price-note{font-size:.8rem;color:var(--text-muted);margin-bottom:24px;min-height:20px}
  .annual-badge{
    display:inline-flex;align-items:center;gap:4px;
    background:rgba(34,197,94,.1);border:1px solid rgba(34,197,94,.2);
    color:var(--green);font-size:.72rem;font-weight:600;
    padding:2px 8px;border-radius:6px;margin-left:8px;
  }
  .feature-list{list-style:none;margin:20px 0 28px;display:flex;flex-direction:column;gap:12px}
  .feature-list li{
    display:flex;align-items:flex-start;gap:10px;
    font-size:.88rem;color:var(--text-secondary);line-height:1.45;
  }
  .feature-list li svg{
    flex-shrink:0;margin-top:2px;
  }
  .cta-btn{
    display:block;width:100%;padding:13px 24px;border:none;border-radius:var(--radius);
    font-size:.92rem;font-weight:600;cursor:pointer;
    transition:all var(--transition);text-align:center;text-decoration:none;
  }
  .cta-outline{
    background:transparent;color:var(--text-primary);
    border:1px solid var(--border-subtle);
  }
  .cta-outline:hover{border-color:var(--accent);color:var(--accent-light);background:rgba(99,102,241,.06)}
  .cta-primary{
    background:linear-gradient(135deg,var(--accent),#7c3aed);
    color:#fff;border:none;
    box-shadow:0 4px 20px var(--accent-glow);
  }
  .cta-primary:hover{
    transform:translateY(-1px);
    box-shadow:0 8px 30px rgba(99,102,241,.35);
  }
  .cta-secondary{
    background:rgba(99,102,241,.1);color:var(--accent-light);
    border:1px solid rgba(99,102,241,.2);
  }
  .cta-secondary:hover{background:rgba(99,102,241,.18)}

  /* ── Comparison Table ── */
  .comparison-section{
    max-width:1100px;margin:0 auto;padding:0 24px 80px;
  }
  .comparison-section h2{
    text-align:center;font-size:1.8rem;font-weight:700;margin-bottom:40px;
    letter-spacing:-.02em;
  }
  .comparison-table{
    width:100%;border-collapse:collapse;
    border:1px solid var(--border-subtle);border-radius:var(--radius-lg);
    overflow:hidden;
  }
  .comparison-table thead th{
    background:var(--bg-card);padding:16px 20px;
    font-size:.82rem;text-transform:uppercase;letter-spacing:1px;
    color:var(--text-muted);font-weight:600;text-align:center;
    border-bottom:1px solid var(--border-subtle);
  }
  .comparison-table thead th:first-child{text-align:left}
  .comparison-table thead th:nth-child(3){
    color:var(--accent-light);
    background:rgba(99,102,241,.06);
  }
  .cat-row{cursor:pointer}
  .cat-row td{
    background:var(--bg-secondary);padding:12px 20px;
    font-size:.82rem;font-weight:700;text-transform:uppercase;
    letter-spacing:.8px;color:var(--text-secondary);
    border-bottom:1px solid var(--border-subtle);
    display:flex;align-items:center;justify-content:space-between;
    user-select:none;transition:background var(--transition);
  }
  .cat-row td:hover{background:var(--bg-card)}
  .cat-chevron{
    transition:transform var(--transition);
    color:var(--text-muted);
  }
  .cat-chevron.open{transform:rotate(180deg)}
  .feat-row td{
    padding:12px 20px;font-size:.88rem;color:var(--text-secondary);
    border-bottom:1px solid var(--border-subtle);
    text-align:center;transition:background var(--transition);
  }
  .feat-row td:first-child{text-align:left;font-weight:500}
  .feat-row:nth-child(even) td{background:rgba(255,255,255,.015)}
  .feat-row:hover td{background:rgba(99,102,241,.04)}
  .feat-row td:nth-child(3){color:var(--accent-light)}
  .feat-row.hidden{display:none}
  .check-cell{
    display:flex;align-items:center;justify-content:center;
  }
  .dash{color:var(--text-muted);font-size:1.1rem}

  /* ── FAQ ── */
  .faq-section{
    max-width:760px;margin:0 auto;padding:0 24px 80px;
  }
  .faq-section h2{
    text-align:center;font-size:1.8rem;font-weight:700;margin-bottom:40px;
    letter-spacing:-.02em;
  }
  .faq-item{
    border:1px solid var(--border-subtle);border-radius:var(--radius);
    margin-bottom:12px;overflow:hidden;
    transition:border-color var(--transition);
  }
  .faq-item:hover{border-color:rgba(99,102,241,.3)}
  .faq-item.open{border-color:rgba(99,102,241,.4)}
  .faq-question{
    width:100%;padding:18px 24px;background:var(--bg-card);
    border:none;color:var(--text-primary);font-size:.95rem;
    font-weight:600;text-align:left;cursor:pointer;
    display:flex;align-items:center;justify-content:space-between;
    gap:16px;transition:background var(--transition);
    font-family:inherit;
  }
  .faq-question:hover{background:var(--bg-card-hover)}
  .faq-question:focus-visible{
    outline:2px solid var(--accent);outline-offset:-2px;
    border-radius:var(--radius);
  }
  .faq-icon{
    flex-shrink:0;transition:transform var(--transition);
    color:var(--text-muted);
  }
  .faq-item.open .faq-icon{transform:rotate(45deg);color:var(--accent-light)}
  .faq-answer{
    max-height:0;overflow:hidden;
    transition:max-height .4s cubic-bezier(.4,0,.2,1),padding .3s ease;
  }
  .faq-answer-inner{
    padding:0 24px 20px;
    font-size:.9rem;color:var(--text-secondary);line-height:1.65;
  }

  /* ── Footer ── */
  footer{
    border-top:1px solid var(--border-subtle);
    padding:48px 24px 32px;
    background:var(--bg-secondary);
  }
  .footer-inner{
    max-width:1100px;margin:0 auto;
    display:flex;align-items:center;justify-content:space-between;
    flex-wrap:wrap;gap:24px;
  }
  .footer-nav{display:flex;gap:28px;flex-wrap:wrap}
  .footer-nav a{
    color:var(--text-secondary);text-decoration:none;font-size:.85rem;
    transition:color var(--transition);
  }
  .footer-nav a:hover{color:var(--text-primary)}
  .footer-bottom{
    max-width:1100px;margin:24px auto 0;
    padding-top:24px;border-top:1px solid var(--border-subtle);
    display:flex;align-items:center;justify-content:space-between;
    flex-wrap:wrap;gap:16px;
  }
  .footer-copy{font-size:.8rem;color:var(--text-muted)}

  /* ── Responsive ── */
  @media(max-width:900px){
    .pricing-grid{grid-template-columns:1fr;max-width:440px}
    .comparison-table{font-size:.82rem}
    .comparison-table thead th,.cat-row td,.feat-row td{padding:10px 12px}
  }
  @media(max-width:600px){
    .header-inner{gap:12px}
    nav{gap:16px}
    nav a{font-size:.82rem}
    .hero{padding:48px 16px 24px}
    .hero h1{font-size:1.8rem}
    .pricing-grid{padding:0 16px 60px}
    .tier-card{padding:28px 20px 24px}
    .price-value{font-size:2.6rem}
    .footer-inner{flex-direction:column;align-items:flex-start}
    .comparison-section{padding:0 16px 60px}
    .faq-section{padding:0 16px 60px}
  }

  /* ── Glow effect behind popular card ── */
  .popular-card-wrap::before{
    content:'';position:absolute;inset:-1px;
    border-radius:var(--radius-lg);z-index:-1;
    background:conic-gradient(from 0deg,#6366f1,#a78bfa,#6366f1,#818cf8,#6366f1);
    animation:spin-border 3s linear infinite;
    filter:blur(12px);opacity:.4;
  }
</style>
</head>
<body>

<!-- ═══ HEADER ═══ -->
<header>
  <div class="header-inner">
    <div class="logo">
      <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
        <path d="M4 12h4l3-8 4 16 3-8h2" stroke="url(#lg)" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"/>
        <defs><linearGradient id="lg" x1="4" y1="4" x2="20" y2="20"><stop stop-color="#818cf8"/><stop offset="1" stop-color="#c084fc"/></linearGradient></defs>
      </svg>
      Conduit
    </div>
    <nav>
      <a href="#pricing">Pricing</a>
      <a href="#features">Features</a>
      <a href="#faq">FAQ</a>
      <span class="status-pill"><span class="status-dot"></span> All systems operational</span>
    </nav>
  </div>
</header>

<!-- ═══ HERO ═══ -->
<section class="hero" id="pricing">
  <h1>Simple pricing that <span>scales with you</span></h1>
  <p>Start free, upgrade when you need to. No hidden fees, no surprises.</p>
</section>

<!-- ═══ TOGGLE ═══ -->
<div class="toggle-wrap">
  <span class="toggle-label active" id="label-monthly" onclick="setBilling('monthly')">Monthly</span>
  <div class="toggle-track" id="toggle-track" onclick="toggleBilling()" role="switch" aria-checked="false" aria-label="Toggle annual billing" tabindex="0">
    <div class="toggle-thumb"></div>
  </div>
  <span class="toggle-label" id="label-annual" onclick="setBilling('annual')">Annual</span>
  <span class="save-badge">Save 20%</span>
</div>

<!-- ═══ PRICING CARDS ═══ -->
<div class="pricing-grid">

  <!-- Starter -->
  <div class="tier-card">
    <div class="tier-name">Starter</div>
    <div class="tier-tagline">Explore Conduit's core integration platform — free forever.</div>
    <div class="price-row">
      <span class="currency">$</span>
      <span class="price-value" data-monthly="0" data-annual="0">0</span>
    </div>
    <div class="price-period">Free forever</div>
    <div class="price-note">&nbsp;</div>
    <ul class="feature-list">
      <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Up to 3 active integrations</li>
      <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>1,000 API calls / month</li>
      <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Community support</li>
      <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Basic monitoring dashboard</li>
      <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>50+ pre-built connectors</li>
      <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Standard data encryption</li>
    </ul>
    <a href="#" class="cta-btn cta-outline">Start free</a>
  </div>

  <!-- Team (Popular) -->
  <div class="popular-card-wrap">
    <span class="popular-tag">Most popular</span>
    <div class="tier-card popular">
      <div class="tier-name">Team</div>
      <div class="tier-tagline">Everything you need to integrate at team scale.</div>
      <div class="price-row">
        <span class="currency">$</span>
        <span class="price-value" data-monthly="29" data-annual="23">29</span>
        <span class="price-period">/ user / mo</span>
      </div>
      <div class="price-note" id="team-note">&nbsp;</div>
      <ul class="feature-list">
        <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Unlimited integrations</li>
        <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>100,000 API calls / month</li>
        <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Priority email &amp; chat support</li>
        <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Advanced analytics &amp; logs</li>
        <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Custom webhook builder</li>
        <li><svg width="18" height="18" viewBox="0 0 18 18" fill="none"><circle cx="9" cy="9" r="8" stroke="#6366f1" stroke-width="1.5"/><path d="M5.5 9l2.5 2.5 4.5-5" stroke="#6366f1" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Team collaboration tools</li>
      </ul>
      <a href="#" class="cta-btn cta-primary">Start free trial</a>
    </div>
  </div>

  <!-- Scale -->
  <div class="tier-card">
    <div class="tier-name">Scale</div>
    <div class="tier-tagline">Enterprise-grade infrastructure for mission-critical operations.</div>
    <div class="price-row">
      <span class="price-value" style="font-size:2rem;letter-spacing:0" data-monthly="Contact" data-annual="Contact">Contact</span>
    </div>
    <div class="price-period">Custom pricing</div>
    <div class="price-note">&nbsp;</div>
    <ul class="feature-list">
