<script>
  let isAnnual = false;

  function toggleBilling() {
    isAnnual = !isAnnual;
    updateBilling();
  }

  function setBilling(mode) {
    isAnnual = mode === 'annual';
    updateBilling();
  }

  function updateBilling() {
    const track = document.getElementById('toggle-track');
    const labelMonthly = document.getElementById('label-monthly');
    const labelAnnual = document.getElementById('label-annual');
    const teamNote = document.getElementById('team-note');

    track.classList.toggle('annual', isAnnual);
    track.setAttribute('aria-checked', isAnnual);
    labelMonthly.classList.toggle('active', !isAnnual);
    labelAnnual.classList.toggle('active', isAnnual);

    // Animate price changes
    const priceEls = document.querySelectorAll('.price-value[data-monthly]');
    priceEls.forEach(el => {
      const newVal = isAnnual ? el.dataset.annual : el.dataset.monthly;
      const currentVal = el.textContent;

      if (newVal !== currentVal) {
        el.classList.add('animating');
        setTimeout(() => {
          el.textContent = newVal;
          el.classList.remove('animating');
        }, 200);
      }
    });

    // Team annual badge
    if (isAnnual) {
      teamNote.innerHTML = '<span class="annual-badge"><svg width="12" height="12" viewBox="0 0 12 12" fill="none"><path d="M2 6l3 3 5-6" stroke="#22c55e" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>Save 20% — billed annually</span>';
    } else {
      teamNote.innerHTML = '&nbsp;';
    }
  }

  // Keyboard support for toggle
  document.getElementById('toggle-track').addEventListener('keydown', function(e) {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      toggleBilling();
    }
  });

  // Comparison table category collapse
  function toggleCategory(row) {
    const chevron = row.querySelector('.cat-chevron');
    const isOpen = chevron.classList.contains('open');
    const category = row.querySelector('span').textContent.trim();
    const catKey = category.toLowerCase();

    if (isOpen) {
      chevron.classList.remove('open');
    } else {
      chevron.classList.add('open');
    }

    // Toggle rows for this category
    document.querySelectorAll('.feat-row').forEach(featRow => {
      if (featRow.dataset.cat === catKey) {
        featRow.classList.toggle('hidden', isOpen);
      }
    });
  }

  // FAQ accordion
  function toggleFaq(button) {
    const item = button.closest('.faq-item');
    const answer = item.querySelector('.faq-answer');
    const isOpen = item.classList.contains('open');

    if (isOpen) {
      item.classList.remove('open');
      button.setAttribute('aria-expanded', 'false');
      answer.style.maxHeight = '0';
    } else {
      item.classList.add('open');
      button.setAttribute('aria-expanded', 'true');
      answer.style.maxHeight = answer.scrollHeight + 'px';
    }
  }

  // Initialize: set max-height for the open FAQ
  document.addEventListener('DOMContentLoaded', function() {
    document.querySelectorAll('.faq-item.open .faq-answer').forEach(answer => {
      answer.style.maxHeight = answer.scrollHeight + 'px';
    });
  });
</script>
</body>
</html>
