    display:flex;align-items:flex-start;gap:10px;
    font-size:.88rem;color:var(--text-secondary);line-height:1.45;
  }
  .feature-list li svg{
    flex-shrink:0;margin-top:2px;
  }
  .cta-btn{
    display:block;width:100%;padding:13px 24px;border:none;border-radius:var(--radius);
    font-size:.92rem;font-weight:600;cursor:pointer;
