  .cat-row td:hover{background:var(--bg-card)}
  .cat-chevron{
    transition:transform var(--transition);
    color:var(--text-muted);
  }
  .cat-chevron.open{transform:rotate(180deg)}
  .feat-row td{
    padding:12px 20px;font-size:.88rem;color:var(--text-secondary);
