    margin-bottom: 2px;
  }

  .screen-title {
    font-family: 'Playfair Display', serif;
    font-size: 1.1rem;
    font-weight: 500;
    color: var(--text);
  }

  /* Breathing indicator */
  .breathing-section {
    display: flex;
    flex-direction: column;
    align-items: center;
    margin: 8px 0 14px;
    padding: 14px 0;
  }

  .breath-ring {
    width: 64px;
    height: 64px;
    border-radius: 50%;
    border: 2px solid var(--teal-dim);
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
  }

  .breath-ring::before {
    content: '';
    position: absolute;
    inset: 4px;
    border-radius: 50%;
    background: var(--teal-subtle);
    animation: breathe 19s ease-in-out infinite;
  }

  .breath-ring::after {
    content: '';
    position: absolute;
    inset: 8px;
    border-radius: 50%;
    background: var(--teal);
    opacity: 0.15;
    animation: breathe 19s ease-in-out infinite;
  }

  @keyframes breathe {
    0%, 4.21% { transform: scale(0.6); opacity: 0.3; }
    10.53%, 14.74% { transform: scale(1); opacity: 0.7; }
    23.68%, 30.26% { transform: scale(0.6); opacity: 0.3; }
    42.11%, 48.68% { transform: scale(1); opacity: 0.7; }
    57.63%, 63.16% { transform: scale(0.6); opacity: 0.3; }
    75.0%, 81.58% { transform: scale(1); opacity: 0.7; }
    90.53%, 96.05% { transform: scale(0.6); opacity: 0.3; }
    100% { transform: scale(0.6); opacity: 0.3; }
  }

  .breath-label {
    font-size: 0.55rem;
    color: var(--teal);
    margin-top: 8px;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    font-weight: 500;
  }

  /* Mood pills */
  .mood-section {
    margin-bottom: 14px;
  }

  .section-label {
    font-size: 0.55rem;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    color: var(--text-muted);
    margin-bottom: 8px;
    font-weight: 600;
  }

  .mood-pills {
    display: flex;
    gap: 6px;
  }

  .mood-pill {
    flex: 1;
    height: 36px;
    border-radius: 12px;
    border: 1px solid var(--border);
    background: var(--bg-card);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    cursor: pointer;
    transition: all 0.3s;
    position: relative;
  }

  .mood-pill.selected {
    border-color: var(--teal);
    background: var(--teal-subtle);
    box-shadow: 0 0 12px rgba(94,196,182,0.15);
  }

  /* Reflection input */
  .reflection-input {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 14px;
    padding: 12px 14px;
    margin-bottom: 14px;
    min-height: 70px;
    position: relative;
  }

  .reflection-placeholder {
    font-size: 0.7rem;
    color: var(--text-muted);
    line-height: 1.5;
  }

  .reflection-placeholder .cursor {
    display: inline-block;
    width: 1.5px;
    height: 12px;
    background: var(--teal);
    margin-left: 1px;
    vertical-align: text-bottom;
    animation: blink 1s step-end infinite;
  }

  @keyframes blink {
    0%, 100% { opacity: 1; }
    50% { opacity: 0; }
  }

  /* Gratitude items */
  .gratitude-section {
    margin-bottom: auto;
  }

  .gratitude-item {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 10px;
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 10px;
    margin-bottom: 6px;
    font-size: 0.65rem;
    color: var(--text-dim);
  }

  .gratitude-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: var(--teal);
    flex-shrink: 0;
  }

  .gratitude-add {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
    padding: 8px;
    border: 1px dashed var(--text-muted);
    border-radius: 10px;
    font-size: 0.6rem;
    color: var(--text-muted);
    cursor: pointer;
    transition: all 0.3s;
  }

  .gratitude-add:hover {
    border-color: var(--teal-dim);
    color: var(--teal);
  }

  /* Submit button */
  .screen-submit {
    width: 100%;
    height: 40px;
    border-radius: 14px;
    background: linear-gradient(135deg, var(--teal), var(--teal-dim));
    border: none;
    color: #0c0d0f;
    font-weight: 600;
    font-size: 0.75rem;
    letter-spacing: 0.03em;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
    margin-top: 12px;
  }

  /* Home indicator */
  .home-indicator {
    position: absolute;
    bottom: 8px;
    left: 50%;
    transform: translateX(-50%);
    width: 100px;
    height: 4px;
    background: rgba(255,255,255,0.15);
    border-radius: 4px;
    z-index: 20;
  }

  /* ── SECTION COMMON ── */
  section {
    padding: 6rem 2rem;
    max-width: 1200px;
    margin: 0 auto;
  }

  .section-header {
    text-align: center;
    margin-bottom: 4rem;
  }

  .section-header h2 {
    font-family: 'Playfair Display', serif;
    font-size: clamp(1.75rem, 3vw, 2.5rem);
    font-weight: 500;
    margin-bottom: 0.75rem;
  }

  .section-header p {
    color: var(--text-dim);
    font-size: 1.05rem;
    max-width: 500px;
    margin: 0 auto;
  }

  /* ── FEATURES ── */
  .features-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
  }

  .feature-card {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 20px;
    padding: 2.5rem 2rem;
    text-align: center;
    transition: all 0.4s;
  }

  .feature-card:hover {
    border-color: rgba(94,196,182,0.2);
    transform: translateY(-4px);
    box-shadow: 0 20px 40px rgba(0,0,0,0.3);
  }

  .feature-icon {
    width: 56px;
    height: 56px;
    margin: 0 auto 1.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 16px;
    background: var(--teal-subtle);
  }

  .feature-card h3 {
    font-size: 1.1rem;
    font-weight: 600;
    margin-bottom: 0.75rem;
  }

  .feature-card p {
    font-size: 0.9rem;
    color: var(--text-dim);
    line-height: 1.6;
  }

  /* ── WEEK GRID ── */
  .week-panel {
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 24px;
    padding: 3rem;
    max-width: 750px;
    margin: 0 auto;
  }

  .week-panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
  }

  .week-panel-header h3 {
    font-family: 'Playfair Display', serif;
    font-size: 1.4rem;
    font-weight: 500;
  }

  .week-nav {
    display: flex;
    gap: 0.5rem;
  }

  .week-nav button {
    width: 32px;
    height: 32px;
    border-radius: 8px;
    border: 1px solid var(--border);
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s;
  }

  .week-nav button:hover {
    border-color: var(--teal-dim);
    color: var(--teal);
  }

  .week-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 12px;
  }

  .day-col {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
  }

  .day-name {
    font-size: 0.65rem;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--text-muted);
    font-weight: 600;
  }

  .day-date {
    font-size: 0.75rem;
    color: var(--text-dim);
  }

  .mood-indicator {
    width: 48px;
    height: 48px;
    border-radius: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.2rem;
    border: 1px solid var(--border);
    background: var(--bg-elevated);
    transition: all 0.3s;
  }

  .mood-indicator.filled {
    border-color: var(--teal-dim);
    background: var(--teal-subtle);
    box-shadow: 0 0 16px rgba(94,196,182,0.1);
  }

  .mood-indicator.empty {
    opacity: 0.3;
  }

  .mood-indicator.today {
    border-color: var(--teal);
    background: rgba(94,196,182,0.12);
    animation: todayPulse 3s ease-in-out infinite;
  }

  @keyframes todayPulse {
    0%, 100% { box-shadow: 0 0 0 0 rgba(94,196,182,0.2); }
    50% { box-shadow: 0 0 0 6px rgba(94,196,182,0); }
  }

  .week-legend {
    display: flex;
    justify-content: center;
    gap: 1.5rem;
    margin-top: 2rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border);
  }

  .legend-item {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 0.7rem;
    color: var(--text-muted);
  }

  .legend-dot {
    width: 8px;
    height: 8px;
    border-radius: 3px;
  }

  /* ── PRICING ── */
  .pricing-strip {
    display: flex;
    gap: 2rem;
    max-width: 700px;
    margin: 0 auto;
  }

  .price-card {
    flex: 1;
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 20px;
    padding: 2.5rem 2rem;
    text-align: center;
    transition: all 0.3s;
    position: relative;
  }

  .price-card.featured {
    border-color: var(--teal);
    background: linear-gradient(180deg, var(--bg-card) 0%, rgba(94,196,182,0.04) 100%);
  }

  .price-card.featured::before {
    content: 'Most Popular';
    position: absolute;
    top: -10px;
    left: 50%;
    transform: translateX(-50%);
    background: var(--teal);
    color: #0c0d0f;
    font-size: 0.65rem;
    font-weight: 700;
    padding: 0.3rem 1rem;
    border-radius: 100px;
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  .price-card:hover {
    transform: translateY(-4px);
  }

  .price-name {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    color: var(--text-dim);
    font-weight: 600;
    margin-bottom: 1rem;
  }

  .price-amount {
    font-size: 2.5rem;
    font-weight: 700;
    margin-bottom: 0.25rem;
  }

  .price-amount .currency {
    font-size: 1.25rem;
    vertical-align: super;
    font-weight: 500;
    color: var(--text-dim);
  }

  .price-period {
    font-size: 0.8rem;
    color: var(--text-muted);
    margin-bottom: 1.5rem;
  }

  .price-features {
    list-style: none;
    text-align: left;
    margin-bottom: 2rem;
  }

  .price-features li {
    font-size: 0.85rem;
    color: var(--text-dim);
    padding: 0.5rem 0;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .price-features li svg {
    flex-shrink: 0;
    opacity: 0.6;
  }

  .price-btn {
    display: block;
    width: 100%;
    height: 44px;
    border-radius: 12px;
    border: none;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s;
    text-decoration: none;
    text-align: center;
    line-height: 44px;
  }

  .price-btn.outline {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--text);
  }

  .price-btn.outline:hover {
    border-color: var(--teal-dim);
    color: var(--teal);
  }

  .price-btn.filled {
    background: linear-gradient(135deg, var(--teal), var(--teal-dim));
    color: #0c0d0f;
  }

  .price-btn.filled:hover {
    box-shadow: 0 8px 24px rgba(94,196,182,0.3);
    transform: translateY(-1px);
  }

  /* ── FOOTER ── */
  footer {
    border-top: 1px solid var(--border);
    padding: 3rem 2rem;
    max-width: 1200px;
    margin: 0 auto;
  }

  .footer-inner {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 1.5rem;
  }

  .footer-brand {
    display: flex;
    align-items: center;
    gap: 1rem;
  }

  .footer-brand .logo {
    font-size: 1.25rem;
  }

  .footer-copy {
    font-size: 0.8rem;
    color: var(--text-muted);
  }

  .footer-links {
    display: flex;
    gap: 2rem;
    list-style: none;
  }

  .footer-links a {
    font-size: 0.8rem;
    color: var(--text-muted);
    text-decoration: none;
    transition: color 0.3s;
  }

  .footer-links a:hover {
    color: var(--teal);
  }

  /* ── RESPONSIVE ── */
  @media (max-width: 900px) {
    .hero {
      flex-direction: column;
      text-align: center;
      padding-top: 7rem;
      gap: 3rem;
    }

    .hero-copy {
      max-width: 100%;
      display: flex;
      flex-direction: column;
      align-items: center;
    }

    .hero-copy p {
      max-width: 100%;
    }

    .features-grid {
      grid-template-columns: 1fr;
      max-width: 400px;
      margin: 0 auto;
    }

    .week-grid {
      gap: 8px;
    }

    .mood-indicator {
      width: 40px;
      height: 40px;
      font-size: 1rem;
      border-radius: 10px;
    }

    .pricing-strip {
      flex-direction: column;
      max-width: 360px;
    }

    .nav-links {
      display: none;
    }
  }

  @media (max-width: 500px) {
    .hero {
      padding: 6rem 1.5rem 3rem;
    }

    section {
      padding: 4rem 1.5rem;
    }

    .week-panel {
      padding: 2rem 1.5rem;
    }

    .badges {
      justify-content: center;
    }

    .footer-inner {
      flex-direction: column;
      text-align: center;
    }
  }

  /* ── AMBIENT GLOW ── */
  .ambient-glow {
    position: fixed;
    width: 600px;
    height: 600px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(94,196,182,0.04) 0%, transparent 70%);
    pointer-events: none;
    z-index: -1;
  }

  .glow-1 {
    top: -200px;
    right: -200px;
  }

  .glow-2 {
    bottom: -200px;
    left: -200px;
  }
</style>
</head>
