    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 24px;
    padding: 3rem;
    max-width: 750px;
    margin: 0 auto;
  }

  .week-panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 2rem;
  }

  .week-panel-header h3 {
    font-family: 'Playfair Display', serif;
    font-size: 1.4rem;
    font-weight: 500;
  }

  .week-nav {
    display: flex;
    gap: 0.5rem;
  }

  .week-nav button {
    width: 32px;
    height: 32px;
    border-radius: 8px;
    border: 1px solid var(--border);
    background: transparent;
    color: var(--text-dim);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s;
  }

  .week-nav button:hover {
    border-color: var(--teal-dim);
    color: var(--teal);
  }

  .week-grid {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 12px;
  }

  .day-col {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 10px;
  }

  .day-name {
    font-size: 0.65rem;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--text-muted);
    font-weight: 600;
  }

  .day-date {
    font-size: 0.75rem;
    color: var(--text-dim);
  }

  .mood-indicator {
    width: 48px;
    height: 48px;
    border-radius: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.2rem;
    border: 1px solid var(--border);
    background: var(--bg-elevated);
    transition: all 0.3s;
  }

  .mood-indicator.filled {
    border-color: var(--teal-dim);
    background: var(--teal-subtle);
    box-shadow: 0 0 16px rgba(94,196,182,0.1);
  }

  .mood-indicator.empty {
    opacity: 0.3;
  }

  .mood-indicator.today {
    border-color: var(--teal);
    background: rgba(94,196,182,0.12);
    animation: todayPulse 3s ease-in-out infinite;
  }

  @keyframes todayPulse {
    0%, 100% { box-shadow: 0 0 0 0 rgba(94,196,182,0.2); }
    50% { box-shadow: 0 0 0 6px rgba(94,196,182,0); }
  }

  .week-legend {
    display: flex;
    justify-content: center;
    gap: 1.5rem;
    margin-top: 2rem;
    padding-top: 1.5rem;
    border-top: 1px solid var(--border);
  }

  .legend-item {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 0.7rem;
    color: var(--text-muted);
  }

  .legend-dot {
    width: 8px;
    height: 8px;
    border-radius: 3px;
  }

  /* ── PRICING ── */
  .pricing-strip {
    display: flex;
    gap: 2rem;
    max-width: 700px;
    margin: 0 auto;
  }

  .price-card {
    flex: 1;
    background: var(--bg-card);
    border: 1px solid var(--border);
    border-radius: 20px;
    padding: 2.5rem 2rem;
    text-align: center;
    transition: all 0.3s;
    position: relative;
  }

  .price-card.featured {
    border-color: var(--teal);
    background: linear-gradient(180deg, var(--bg-card) 0%, rgba(94,196,182,0.04) 100%);
  }

  .price-card.featured::before {
    content: 'Most Popular';
    position: absolute;
    top: -10px;
    left: 50%;
    transform: translateX(-50%);
    background: var(--teal);
    color: #0c0d0f;
    font-size: 0.65rem;
    font-weight: 700;
    padding: 0.3rem 1rem;
    border-radius: 100px;
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  .price-card:hover {
    transform: translateY(-4px);
  }

  .price-name {
    font-size: 0.8rem;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    color: var(--text-dim);
    font-weight: 600;
    margin-bottom: 1rem;
  }

  .price-amount {
    font-size: 2.5rem;
    font-weight: 700;
    margin-bottom: 0.25rem;
  }

  .price-amount .currency {
    font-size: 1.25rem;
    vertical-align: super;
    font-weight: 500;
    color: var(--text-dim);
  }

  .price-period {
    font-size: 0.8rem;
    color: var(--text-muted);
    margin-bottom: 1.5rem;
  }

  .price-features {
    list-style: none;
    text-align: left;
    margin-bottom: 2rem;
  }

  .price-features li {
    font-size: 0.85rem;
    color: var(--text-dim);
    padding: 0.5rem 0;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .price-features li svg {
    flex-shrink: 0;
    opacity: 0.6;
  }

  .price-btn {
    display: block;
    width: 100%;
    height: 44px;
    border-radius: 12px;
    border: none;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s;
    text-decoration: none;
    text-align: center;
    line-height: 44px;
  }

  .price-btn.outline {
    background: transparent;
    border: 1px solid var(--border);
    color: var(--text);
  }

  .price-btn.outline:hover {
    border-color: var(--teal-dim);
    color: var(--teal);
  }

  .price-btn.filled {
    background: linear-gradient(135deg, var(--teal), var(--teal-dim));
    color: #0c0d0f;
  }

  .price-btn.filled:hover {
    box-shadow: 0 8px 24px rgba(94,196,182,0.3);
    transform: translateY(-1px);
  }

  /* ── FOOTER ── */
  footer {
    border-top: 1px solid var(--border);
    padding: 3rem 2rem;
    max-width: 1200px;
    margin: 0 auto;
  }

  .footer-inner {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: 1.5rem;
  }

  .footer-brand {
    display: flex;
    align-items: center;
    gap: 1rem;
  }

  .footer-brand .logo {
    font-size: 1.25rem;
  }

  .footer-copy {
    font-size: 0.8rem;
    color: var(--text-muted);
  }

  .footer-links {
    display: flex;
    gap: 2rem;
    list-style: none;
  }

  .footer-links a {
    font-size: 0.8rem;
    color: var(--text-muted);
