    transition: color 0.3s;
  }

  .footer-links a:hover {
    color: var(--teal);
  }

  /* ── RESPONSIVE ── */
  @media (max-width: 900px) {
    .hero {
      flex-direction: column;
      text-align: center;
      padding-top: 7rem;
      gap: 3rem;
    }

    .hero-copy {
