    }

    .pricing-strip {
      flex-direction: column;
      max-width: 360px;
    }

    .nav-links {
      display: none;
    }
  }

  @media (max-width: 500px) {
    .hero {
      padding: 6rem 1.5rem 3rem;
    }

    section {
