<script>
(function () {
  "use strict";

  var canvas = document.getElementById("c");
  var ctx = canvas.getContext("2d");

  var N = 3000;
  var BASE_HUE = 200;
  var HUE_SPREAD = 40;
  var SATURATION = 85;
  var LIGHTNESS = 60;
  var PARTICLE_ALPHA = 0.10;
  var TRAIL_ALPHA = 0.035;
  var ATTRACT = 0.012;
  var DAMPING = 0.985;
  var REPULSE_RADIUS = 60;
  var REPULSE_STRENGTH = 0.15;

  var x = new Float32Array(N);
  var vx = new Float32Array(N);
  var hue = new Float32Array(N);
  var size = new Float32Array(N);

  var mouse = { x: -9999, y: -9999 };
  var target = { x: 0, y: 0 };
  var hasMoved = false;
  var W = 0, H = 0, dpr = 1;

  function init() {
    dpr = window.devicePixelRatio || 1;
    W = window.innerWidth;
    H = window.innerHeight;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

    target.x = W / 2;
    target.y = H / 2;
    mouse.x = W / 2;
    mouse.y = H / 2;

    for (var i = 0; i < N; i++) {
      x[i] = W / 2 + (Math.random() - 0.5) * Math.min(W, H) * 0.5;
      vx[i] = (Math.random() - 0.5) * 2;
      hue[i] = BASE_HUE + (Math.random() - 0.5) * HUE_SPREAD;
      size[i] = 1.2 + Math.random() * 2.2;
    }
  }

  function update(dt) {
    var cx = target.x;
    var cy = target.y;

    for (var i = 0; i < N; i++) {
      var px = x[i];
      var py = x[i + N];

      var dx = cx - px;
      var dy = cy - py;
      var distSq = dx * dx + dy * dy;
      var dist = Math.sqrt(distSq) || 1;

      var ax = 0;
      var ay = 0;

      if (dist < REPULSE_RADIUS) {
        var t = 1 - dist / REPULSE_RADIUS;
        t = t * t;
        ax -= (dx / dist) * t * REPULSE_STRENGTH;
        ay -= (dy / dist) * t * REPULSE_STRENGTH;
      } else {
        ax += (dx / dist) * ATTRACT * (1 + 2 / (1 + dist * 0.005));
        ay += (dy / dist) * ATTRACT * (1 + 2 / (1 + dist * 0.005));
      }

      vx[i] += ax * dt;
      vx[i + N] += ay * dt;

      vx[i] *= Math.pow(DAMPING, dt);
      vx[i + N] *= Math.pow(DAMPING, dt);

      x[i] += vx[i] * dt;
      x[i + N] += vx[i + N] * dt;

      if (x[i] < -50) x[i] = -50;
      if (x[i] > W + 50) x[i] = W + 50;
      if (x[i + N] < -50) x[i + N] = -50;
      if (x[i + N] > H + 50) x[i + N] = H + 50;
    }
  }

  var BATCH = 100;

  function draw() {
    ctx.fillStyle = "rgba(2, 2, 6," + TRAIL_ALPHA + ")";
    ctx.fillRect(0, 0, W, H);

    ctx.globalCompositeOperation = "lighter";

    for (var start = 0; start < N; start += BATCH) {
      var end = Math.min(start + BATCH, N);
      var h = hue[start];
      ctx.fillStyle = "hsla(" + h + "," + SATURATION + "%," + LIGHTNESS + "%," + PARTICLE_ALPHA + ")";

      for (var i = start; i < end; i++) {
        if (hue[i] !== h) {
          h = hue[i];
          ctx.fillStyle = "hsla(" + h + "," + SATURATION + "%," + LIGHTNESS + "%," + PARTICLE_ALPHA + ")";
        }
        ctx.fillRect(x[i] - size[i] * 0.5, x[i + N] - size[i] * 0.5, size[i], size[i]);
      }
    }

    ctx.globalCompositeOperation = "source-over";
  }

  var lastTime = 0;

  function loop(now) {
    if (lastTime === 0) lastTime = now;
    var dt = Math.min((now - lastTime) / 16.667, 3);
    lastTime = now;

    update(dt);
    draw();
    requestAnimationFrame(loop);
  }

  canvas.addEventListener("mousemove", function (e) {
    target.x = e.clientX;
    target.y = e.clientY;
    hasMoved = true;
  });

  canvas.addEventListener("touchmove", function (e) {
    e.preventDefault();
    var touch = e.touches[0];
    target.x = touch.clientX;
    target.y = touch.clientY;
    hasMoved = true;
  }, { passive: false });

  canvas.addEventListener("touchstart", function (e) {
    e.preventDefault();
    var touch = e.touches[0];
    target.x = touch.clientX;
    target.y = touch.clientY;
    hasMoved = true;
  }, { passive: false });

  window.addEventListener("resize", function () {
    var oldW = W;
    var oldH = H;
    dpr = window.devicePixelRatio || 1;
    W = window.innerWidth;
    H = window.innerHeight;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    ctx.fillStyle = "rgba(2, 2, 6,1)";
    ctx.fillRect(0, 0, W, H);

    var sx = W / oldW;
    var sy = H / oldH;
    for (var i = 0; i < N; i++) {
      x[i] *= sx;
      x[i + N] *= sy;
      if (x[i] < 0) x[i] = 0;
      if (x[i] > W) x[i] = W;
      if (x[i + N] < 0) x[i + N] = 0;
      if (x[i + N] > H) x[i + N] = H;
    }

    target.x = Math.min(Math.max(target.x * sx, 0), W);
    target.y = Math.min(Math.max(target.y * sy, 0), H);
    mouse.x = target.x;
    mouse.y = target.y;
  });

  init();
  requestAnimationFrame(loop);
})();
</script>
</body>
</html>
