<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Crystal Shards</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  canvas { display: block; width: 100%; height: 100%; }
</style>
</head>
<body>
<canvas id="canvas"></canvas>
<script type="importmap">
{
  "imports": {
    "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
    "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
  }
}
</script>
<script type="module">
import * as THREE from 'three';
import { EffectComposer } from 'three/addons/postprocessing/EffectComposer.js';
import { RenderPass } from 'three/addons/postprocessing/RenderPass.js';
import { UnrealBloomPass } from 'three/addons/postprocessing/UnrealBloomPass.js';
import { RoomEnvironment } from 'three/addons/environments/RoomEnvironment.js';

// ── Renderer ──
const canvas = document.getElementById('canvas');
const renderer = new THREE.WebGLRenderer({
  canvas,
  antialias: true,
  alpha: false,
  powerPreference: 'high-performance'
});
renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
renderer.setSize(window.innerWidth, window.innerHeight);
renderer.toneMapping = THREE.ACESFilmicToneMapping;
renderer.toneMappingExposure = 1.2;
renderer.outputColorSpace = THREE.SRGBColorSpace;

// ── Scene ──
const scene = new THREE.Scene();

// Background gradient
const bgCanvas = document.createElement('canvas');
bgCanvas.width = 2;
bgCanvas.height = 512;
const bgCtx = bgCanvas.getContext('2d');
const grad = bgCtx.createLinearGradient(0, 0, 0, 512);
grad.addColorStop(0, '#0a0a1a');
grad.addColorStop(0.5, '#050510');
grad.addColorStop(1, '#020208');
bgCtx.fillStyle = grad;
bgCtx.fillRect(0, 0, 2, 512);
const bgTexture = new THREE.CanvasTexture(bgCanvas);
bgTexture.colorSpace = THREE.SRGBColorSpace;
scene.background = bgTexture;

// ── Camera ──
const camera = new THREE.PerspectiveCamera(50, window.innerWidth / window.innerHeight, 0.1, 100);
camera.position.set(0, 0, 12);

// ── Environment Map ──
const pmremGenerator = new THREE.PMREMGenerator(renderer);
pmremGenerator.compileEquirectangularShader();
const roomEnv = new RoomEnvironment();
const envMap = pmremGenerator.fromScene(roomEnv, 0.04).texture;
scene.environment = envMap;
roomEnv.dispose();
pmremGenerator.dispose();

// ── Lighting ──
// Key light — warm
const keyLight = new THREE.DirectionalLight(0xffeedd, 3.5);
keyLight.position.set(5, 8, 5);
scene.add(keyLight);

// Fill light — cool
const fillLight = new THREE.DirectionalLight(0x4488cc, 1.8);
fillLight.position.set(-6, -2, -4);
scene.add(fillLight);

// Subtle rim/back light
const rimLight = new THREE.DirectionalLight(0x8866ff, 1.2);
rimLight.position.set(0, -5, -8);
scene.add(rimLight);

// Soft ambient
const ambient = new THREE.AmbientLight(0x222244, 0.5);
scene.add(ambient);

// ── Crystal Shards ──
const shardCount = 7;
const shards = [];
const colors = [
  new THREE.Color(0x88ccff), // blue
  new THREE.Color(0xff88aa), // pink
  new THREE.Color(0x88ffcc), // mint
  new THREE.Color(0xffdd88), // amber
  new THREE.Color(0xaa88ff), // violet
  new THREE.Color(0x88ffdd), // teal
  new THREE.Color(0xff88cc), // rose
];

for (let i = 0; i < shardCount; i++) {
  const angle = (i / shardCount) * Math.PI * 2;
  const radius = 3.0 + (i % 3) * 0.6;
  const yOffset = (i - 3) * 0.7;
  const zOffset = Math.sin(angle * 2.3) * 1.5;

  const geometry = new THREE.IcosahedronGeometry(0.5 + Math.random() * 0.3, 0);
  const scale = 0.8 + Math.random() * 0.6;

  const material = new THREE.MeshPhysicalMaterial({
    color: colors[i],
    metalness: 0.0,
    roughness: 0.05,
    transmission: 0.95,
    thickness: 1.5,
    ior: 1.5,
    clearcoat: 1.0,
    clearcoatRoughness: 0.05,
    transparent: true,
    opacity: 0.92,
    envMapIntensity: 1.5,
    side: THREE.DoubleSide,
    depthWrite: false,
  });

  const mesh = new THREE.Mesh(geometry, material);
  mesh.scale.set(scale, scale * (0.7 + Math.random() * 0.6), scale);
  mesh.position.set(
    Math.cos(angle) * radius,
    yOffset,
    Math.sin(angle) * radius + zOffset
  );
  mesh.rotation.set(
    Math.random() * Math.PI,
    Math.random() * Math.PI,
    Math.random() * Math.PI
  );

  scene.add(mesh);

  shards.push({
    mesh,
    basePos: mesh.position.clone(),
    orbitAngle: angle,
    orbitRadius: radius,
    orbitSpeed: 0.08 + Math.random() * 0.06,
    bobSpeed: 0.4 + Math.random() * 0.3,
    bobAmount: 0.3 + Math.random() * 0.4,
    rotSpeed: new THREE.Vector3(
      (Math.random() - 0.5) * 0.5,
      (Math.random() - 0.5) * 0.5,
      (Math.random() - 0.5) * 0.5
    ),
    phaseOffset: Math.random() * Math.PI * 2,
    tiltPhase: Math.random() * Math.PI * 2,
  });
}

// ── Post-processing ──
const composer = new EffectComposer(renderer);
const renderPass = new RenderPass(scene, camera);
composer.addPass(renderPass);

const bloomPass = new UnrealBloomPass(
  new THREE.Vector2(window.innerWidth, window.innerHeight),
  0.8,   // strength
  0.6,   // radius
  0.75   // threshold
);
composer.addPass(bloomPass);

// ── Resize ──
function onResize() {
  const w = window.innerWidth;
  const h = window.innerHeight;
  camera.aspect = w / h;
  camera.updateProjectionMatrix();
  renderer.setSize(w, h);
  composer.setSize(w, h);
  bloomPass.resolution.set(w, h);
}
window.addEventListener('resize', onResize);

// ── Animation ──
const clock = new THREE.Clock();

function animate() {
  requestAnimationFrame(animate);
  const t = clock.getElapsedTime();

  // Slow camera orbit
  const camAngle = t * 0.12;
  camera.position.x = Math.sin(camAngle) * 12;
  camera.position.z = Math.cos(camAngle) * 12;
  camera.position.y = Math.sin(t * 0.07) * 1.5 + 1.0;
  camera.lookAt(0, 0, 0);

  // Update shards
  for (let i = 0; i < shards.length; i++) {
    const s = shards[i];
    const a = s.orbitAngle + t * s.orbitSpeed;

    // Orbital motion
    s.mesh.position.x = Math.cos(a) * s.orbitRadius;
    s.mesh.position.z = Math.sin(a) * s.orbitRadius;

    // Gentle bobbing
    s.mesh.position.y = s.basePos.y +
      Math.sin(t * s.bobSpeed + s.phaseOffset) * s.bobAmount;

    // Rotation
    s.mesh.rotation.x += s.rotSpeed.x * 0.016;
    s.mesh.rotation.y += s.rotSpeed.y * 0.016;
    s.mesh.rotation.z += s.rotSpeed.z * 0.016;

    // Gentle tilt oscillation
    s.mesh.rotation.x += Math.sin(t * 0.3 + s.tiltPhase) * 0.002;
    s.mesh.rotation.z += Math.cos(t * 0.25 + s.tiltPhase) * 0.0015;
  }

  composer.render();
}

animate();
</script>
</body>
</html>
