  new THREE.Color(0x88ccff), // blue
  new THREE.Color(0xff88aa), // pink
  new THREE.Color(0x88ffcc), // mint
  new THREE.Color(0xffdd88), // amber
  new THREE.Color(0xaa88ff), // violet
  new THREE.Color(0x88ffdd), // teal
  new THREE.Color(0xff88cc), // rose
