"use strict";

/* ── Shader sources ─────────────────────────────────────────── */

const VS = `#version 300 es
in vec2 a_pos;
out vec2 v_uv;
void main() {
  v_uv = a_pos * 0.5 + 0.5;
  gl_Position = vec4(a_pos, 0.0, 1.0);
}`;

const FS = `#version 300 es
precision highp float;

in vec2 v_uv;
out vec4 fragColor;

uniform vec2 u_res;
uniform float u_time;

/* ── SDF primitives ─────────────────────────────────────── */

float sdSphere(vec3 p, float r) {
  return length(p) - r;
}

float sdTorus(vec3 p, vec2 t) {
  vec2 q = vec2(length(p.xz) - t.x, p.y);
  return length(q) - t.y;
}

/* ── Smooth minimum ─────────────────────────────────────── */

float smin(float a, float b, float k) {
  float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);
  return mix(b, a, h) - k * h * (1.0 - h);
}

vec3 sminGrad(float da, float db, float ka, float kb, float k) {
  float h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0);
  return mix(db * kb, da * ka, h) - k * h * (1.0 - h) * (kb - ka);
}

/* ── Scene ──────────────────────────────────────────────── */

float mapShape(vec3 p, out vec3 n) {
  // Morphing sphere
  float t = u_time;
  float morph = 1.0 + 0.35 * sin(t * 0.7) * sin(p.x * 3.0) * sin(p.y * 3.0) * sin(p.z * 3.0);
  float sphereR = 1.2 * morph;
  vec3 sp = p - vec3(0.0, 1.5 + 0.3 * sin(t * 0.5), 0.0);
  float dS = sdSphere(sp, sphereR);

  // Torus with slow rotation
  float a = t * 0.3;
  vec3 tp = p;
  tp.xz = mat2(cos(a), -sin(a), sin(a), cos(a)) * tp.xz;
  float dT = sdTorus(tp - vec3(0.0, 0.6, 0.0), vec2(1.5, 0.35));

  // Smooth union
  float k = 1.2;
  float d = smin(dS, dT, k);

  // Ground plane
  float dG = p.y + 0.01;

  // Return min of shape and ground
  if (d < dG) {
    // Numerical gradient for the shape
    vec2 e = vec2(0.001, 0.0);
    n = normalize(vec3(
      dS - sdSphere(sp - e.xyy, sphereR),
      dS - sdSphere(sp - e.yxy, sphereR),
      dS - sdSphere(sp - e.yyx, sphereR)
    ));
    return d;
  } else {
    n = vec3(0.0, 1.0, 0.0);
    return dG;
  }
}

/* ── Checker pattern ────────────────────────────────────── */

vec3 checker(vec3 p, vec3 n) {
  float scale = 0.5;
  vec2 ip = floor(p.xz / scale);
  float c = mod(ip.x + ip.y, 2.0);
  return mix(vec3(0.75, 0.72, 0.68), vec3(0.45, 0.42, 0.38), c);
}

/* ── Raymarching ────────────────────────────────────────── */

#define MAX_STEPS 128
#define MAX_DIST  50.0
#define SURF_DIST 0.001

void main() {
  vec2 uv = (gl_FragCoord.xy - 0.5 * u_res) / u_res.y;

