  vec3 ro = vec3(sin(camT) * camR, 2.8 + 0.3 * sin(u_time * 0.25), cos(camT) * camR);
  vec3 target = vec3(0.0, 0.8, 0.0);
  vec3 fwd = normalize(target - ro);
  vec3 right = normalize(cross(fwd, vec3(0.0, 1.0, 0.0)));
  vec3 up = cross(right, fwd);
  vec3 rd = normalize(fwd * 1.8 + right * uv.x + up * uv.y);

  // March
  float t = 0.0;
  vec3 n = vec3(0.0);
  bool hit = false;
  for (int i = 0; i < MAX_STEPS; i++) {
    vec3 p = ro + rd * t;
    t += mapShape(p, n);
    if (t > MAX_DIST || t < SURF_DIST) break;
  }

  // Background gradient
  float bgT = rd.y * 0.5 + 0.5;
  vec3 bg = mix(vec3(0.55, 0.72, 0.92), vec3(0.15, 0.20, 0.38), bgT);
  // Subtle sky detail
  bg += 0.05 * sin(rd.x * 8.0 + rd.z * 6.0) * max(0.0, rd.y);

  vec3 col = bg;

  if (t < MAX_DIST) {
    vec3 p = ro + rd * t;

    // Determine surface type
    bool isGround = abs(p.y + 0.01) < 0.1;

    // Base color
    vec3 baseColor;
    if (isGround) {
      baseColor = checker(p, n);
    } else {
      // Shape color: gradient based on position
      float hue = fract(length(p.xz) * 0.15 + p.y * 0.08 + u_time * 0.05);
      vec3 c1 = vec3(0.92, 0.32, 0.28);  // warm orange
      vec3 c2 = vec3(0.22, 0.58, 0.90);  // blue
      vec3 c3 = vec3(0.85, 0.22, 0.55);  // purple
      baseColor = mix(c1, c2, smoothstep(0.0, 0.5, hue));
      baseColor = mix(baseColor, c3, smoothstep(0.5, 1.0, hue));
    }

    // Lighting
    vec3 L1 = normalize(vec3(
      cos(u_time * 0.4),
      0.6 + 0.3 * sin(u_time * 0.3),
      sin(u_time * 0.4)
    ));

    // Ambient
    vec3 ambient = vec3(0.08, 0.10, 0.15);

    // Diffuse (Lambert)
    float NdotL = max(dot(n, L1), 0.0);
    vec3 diffuse = NdotL * vec3(0.95, 0.88, 0.78);

    // Specular (Blinn-Phong)
    vec3 V = normalize(ro - p);
    vec3 H = normalize(L1 + V);
    float spec = pow(max(dot(n, H), 0.0), 48.0);
    vec3 specular = spec * vec3(0.9, 0.88, 0.85);

