  col = col / (1.0 + col);

  // Gamma
  col = pow(col, vec3(1.0 / 2.2));

  // Vignette
  vec2 vuv = gl_FragCoord.xy / u_res;
  float vig = 1.0 - 0.35 * pow(length(vuv - 0.5) * 1.4, 2.0);
  col *= vig;

  fragColor = vec4(col, 1.0);
}`;

/* ── WebGL bootstrap ─────────────────────────────────────── */

const canvas = document.getElementById("gl");
const logEl  = document.getElementById("log");
const gl     = canvas.getContext("webgl2", { antialias: true, alpha: false });

if (!gl) {
  logEl.textContent = "WebGL2 not supported by this browser.";
  logEl.classList.add("visible");
  throw new Error("WebGL2 unavailable");
}

function logError(msg) {
  console.error(msg);
  logEl.textContent += msg + "\n";
  logEl.classList.add("visible");
}

function compileShader(src, type) {
  const s = gl.createShader(type);
  gl.shaderSource(s, src);
  gl.compileShader(s);
  if (!gl.getShaderParameter(s, gl.COMPILE_STATUS)) {
    const log = gl.getShaderInfoLog(s);
    logError(`Shader compile error (${type === gl.VERTEX_SHADER ? "VS" : "FS"}):\n${log}`);
    gl.deleteShader(s);
    return null;
  }
  return s;
}

const vs = compileShader(VS, gl.VERTEX_SHADER);
const fs = compileShader(FS, gl.FRAGMENT_SHADER);

if (!vs || !fs) {
  throw new Error("Shader compilation failed — see log.");
}

const prog = gl.createProgram();
gl.attachShader(prog, vs);
gl.attachShader(prog, fs);
gl.linkProgram(prog);

if (!gl.getProgramParameter(prog, gl.LINK_STATUS)) {
  const log = gl.getProgramInfoLog(prog);
  logError(`Program link error:\n${log}`);
  throw new Error("Program linking failed — see log.");
}

gl.deleteShader(vs);
gl.deleteShader(fs);

/* ── Geometry (fullscreen quad) ─────────────────────────── */

const quad = new Float32Array([-1,-1, 1,-1, -1,1, 1,1]);
const buf  = gl.createBuffer();
gl.bindBuffer(gl.ARRAY_BUFFER, buf);
gl.bufferData(gl.ARRAY_BUFFER, quad, gl.STATIC_DRAW);

const aPos = gl.getAttribLocation(prog, "a_pos");

/* ── Uniforms ────────────────────────────────────────────── */

const uRes   = gl.getUniformLocation(prog, "u_res");
const uTime  = gl.getUniformLocation(prog, "u_time");

/* ── Resize / DPR ────────────────────────────────────────── */

function resize() {
  const dpr = window.devicePixelRatio || 1;
  const w = window.innerWidth  * dpr;
  const h = window.innerHeight * dpr;
  if (canvas.width !== w || canvas.height !== h) {
    canvas.width  = w;
    canvas.height = h;
  }
  gl.viewport(0, 0, w, h);
}

window.addEventListener("resize", resize);
resize();

/* ── Render loop ─────────────────────────────────────────── */

const t0 = performance.now();

function frame() {
  const time = (performance.now() - t0) * 0.001;

  gl.clearColor(0.1, 0.12, 0.18, 1.0);
  gl.clear(gl.COLOR_BUFFER_BIT);

  gl.useProgram(prog);

  gl.bindBuffer(gl.ARRAY_BUFFER, buf);
  gl.enableVertexAttribArray(aPos);
  gl.vertexAttribPointer(aPos, 2, gl.FLOAT, false, 0, 0);

  gl.uniform2f(uRes, canvas.width, canvas.height);
  gl.uniform1f(uTime, time);

  gl.drawArrays(gl.TRIANGLE_STRIP, 0, 4);

  requestAnimationFrame(frame);
}

requestAnimationFrame(frame);
</script>
</body>
</html>
```

**What this does:**

- **Vertex shader** renders a fullscreen quad, passing UV coordinates to the fragment shader.
- **Fragment shader** raymarches a scene containing:
  - A **morphing sphere** that deforms with a time-varying sine function (wobbles organically)
  - A **rotating torus** that spins slowly around the Y axis
  - The two shapes are blended with a **smooth minimum** (`smin`) for a seamless organic union
  - A **ground plane** with a checkerboard pattern
- **Lighting**: Blinn-Phong model (ambient + Lambert diffuse + specular) with one directional light orbiting the scene
- **Visual polish**: Distance fog, Reinhard tone mapping, gamma correction, vignette, sky gradient
- **Camera** slowly orbits the scene
- **Error handling**: Shader compile/link failures are caught and displayed both in the console and an on-page `<pre>` tag
- **DPR/resize**: Handled via `devicePixelRatio` and a resize listener

