  const COLS = 24;
  const ROWS = 16;
  const CONSTRAINT_ITERATIONS = 7;
  const GRAVITY = 500;
  const DAMPING = 0.997;
  const MOUSE_RADIUS = 60;
  const MOUSE_FORCE = 8.0;
  const CUTOFF_DIST = 14;
  const PIN_COUNT = 4;

  const canvas = document.getElementById('c');
  const ctx = canvas.getContext('2d');

  let W, H, dpr, spacing, points, constraints, pinSet;
  let mouse = { x: 0, y: 0, down: false, right: false, px: 0, py: 0 };
  let dragging = false;
  let dragPoint = null;
  let lastTime = 0;
  let frameCount = 0;

  // ---- Initialization ----

  function initPoints() {
    const padX = 100;
    const padTop = 80;
    const availW = W - padX * 2;
    const availH = H - padTop * 2;
    spacing = Math.min(availW / (COLS - 1), availH / (ROWS - 1), 38);
    const clothW = spacing * (COLS - 1);
    const clothH = spacing * (ROWS - 1);
    const ox = (W - clothW) / 2;
    const oy = padTop;

    points = new Float64Array(COLS * ROWS * 8);
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        const i = r * COLS + c;
        const px = ox + c * spacing;
        const py = oy + r * spacing;
        points[i * 8 + 0] = px;     // x
        points[i * 8 + 1] = py;     // y
        points[i * 8 + 2] = px;     // px
        points[i * 8 + 3] = py;     // py
        points[i * 8 + 4] = 0;      // fx
        points[i * 8 + 5] = 0;      // fy
        points[i * 8 + 6] = 0;      // vx
        points[i * 8 + 7] = 0;      // vy
      }
    }
  }

  function initConstraints() {
    constraints = [];
    for (let r = 0; r < ROWS; r++) {
      for (let c = 0; c < COLS; c++) {
        if (c + 1 < COLS) {
          constraints.push([r * COLS + c, r * COLS + c + 1, spacing]);
        }
        if (r + 1 < ROWS) {
          constraints.push([r * COLS + c, (r + 1) * COLS + c, spacing]);
        }
      }
    }
  }

  function initPins() {
    pinSet = new Uint8Array(COLS * ROWS);
    if (COLS <= PIN_COUNT) {
      for (let c = 0; c < COLS; c++) pinSet[c] = 1;
    } else {
      for (let k = 0; k < PIN_COUNT; k++) {
        pinSet[Math.floor(k * (COLS - 1) / (PIN_COUNT - 1))] = 1;
      }
    }
  }

  function init() {
    dpr = window.devicePixelRatio || 1;
    W = window.innerWidth;
    H = window.innerHeight;
    canvas.width = W * dpr;
    canvas.height = H * dpr;
    canvas.style.width = W + 'px';
    canvas.style.height = H + 'px';
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
    initPoints();
    initConstraints();
    initPins();
  }

  // ---- Simulation ----

  function simulate(dt) {
    dt = Math.min(dt, 1 / 30);
    const dtSq = dt * dt;

    // Accumulate forces (reset)
    for (let i = 0; i < COLS * ROWS; i++) {
      points[i * 8 + 4] = 0;
      points[i * 8 + 5] = 0;
      // Gravity
      points[i * 8 + 5] += GRAVITY;
    }

    // Mouse force
    if (mouse.down && !mouse.right) {
      for (let i = 0; i < COLS * ROWS; i++) {
        const dx = mouse.x - points[i * 8 + 0];
        const dy = mouse.y - points[i * 8 + 1];
        const d = Math.sqrt(dx * dx + dy * dy);
        if (d < MOUSE_RADIUS && d > 0.1) {
          const f = MOUSE_FORCE * (1 - d / MOUSE_RADIUS);
          points[i * 8 + 4] += (dx / d) * f * 600;
          points[i * 8 + 5] += (dy / d) * f * 600;
        }
      }
    }

    // Verlet integration
    for (let i = 0; i < COLS * ROWS; i++) {
      if (pinSet[i]) continue;

      const cx = points[i * 8 + 0];
      const cy = points[i * 8 + 1];
      const cpx = points[i * 8 + 2];
      const cpy = points[i * 8 + 3];
      const fx = points[i * 8 + 4];
      const fy = points[i * 8 + 5];

      let nx = (2 * cx - cpx + fx * dtSq);
      let ny = (2 * cy - cpy + fy * dtSq);

      // Clamp velocity to prevent explosions
      let vx = nx - cx;
      let vy = ny - cy;
      const speed = Math.sqrt(vx * vx + vy * vy);
      const maxSpeed = 800 * dt;
      if (speed > maxSpeed) {
        const s = maxSpeed / speed;
        nx = cx + vx * s;
        ny = cy + vy * s;
      }

      points[i * 8 + 2] = cx;
      points[i * 8 + 3] = cy;
      points[i * 8 + 0] = nx;
      points[i * 8 + 1] = ny;
    }

    // Boundary clamping
    const margin = 5;
    for (let i = 0; i < COLS * ROWS; i++) {
      if (pinSet[i]) continue;
      points[i * 8 + 0] = Math.max(margin, Math.min(W - margin, points[i * 8 + 0]));
      points[i * 8 + 1] = Math.max(margin, Math.min(H - margin, points[i * 8 + 1]));
    }

    // Constraint solving
    for (let iter = 0; iter < CONSTRAINT_ITERATIONS; iter++) {
      for (let ci = 0; ci < constraints.length; ci++) {
        const ref = constraints[ci];
        if (!ref) continue;
        const ai = ref[0];
        const bi = ref[1];
        const target = ref[2];

        const ax = points[ai * 8 + 0];
        const ay = points[ai * 8 + 1];
        const bx = points[bi * 8 + 0];
        const by = points[bi * 8 + 1];

        const dx = bx - ax;
        const dy = by - ay;
        const dist = Math.sqrt(dx * dx + dy * dy);
        if (dist < 0.0001) continue;

        const diff = (target - dist) / dist * 0.5;
        const ox = dx * diff;
        const oy = dy * diff;

        if (!pinSet[ai]) {
          points[ai * 8 + 0] -= ox;
          points[ai * 8 + 1] -= oy;
        }
        if (!pinSet[bi]) {
          points[bi * 8 + 0] += ox;
          points[bi * 8 + 1] += oy;
        }
      }

      // Re-apply boundary after constraints
      for (let i = 0; i < COLS * ROWS; i++) {
        if (pinSet[i]) continue;
        points[i * 8 + 0] = Math.max(margin, Math.min(W - margin, points[i * 8 + 0]));
        points[i * 8 + 1] = Math.max(margin, Math.min(H - margin, points[i * 8 + 1]));
      }
    }
  }

  // ---- Rendering ----

  function getStrain(i) {
    const cx = points[i * 8 + 0];
    const cy = points[i * 8 + 1];
    const cpx = points[i * 8 + 2];
    const cpy = points[i * 8 + 3];
    const vx = cx - cpx;
    const vy = cy - cpy;
    return Math.sqrt(vx * vx + vy * vy);
  }

  function render() {
    ctx.clearRect(0, 0, W, H);

    // Draw quads with gradient fill
    for (let r = 0; r < ROWS - 1; r++) {
      for (let c = 0; c < COLS - 1; c++) {
        const i00 = r * COLS + c;
        const i10 = i00 + 1;
        const i01 = (r + 1) * COLS + c;
        const i11 = i01 + 1;

        const x00 = points[i00 * 8 + 0], y00 = points[i00 * 8 + 1];
        const x10 = points[i10 * 8 + 0], y10 = points[i10 * 8 + 1];
        const x01 = points[i01 * 8 + 0], y01 = points[i01 * 8 + 1];
        const x11 = points[i11 * 8 + 0], y11 = points[i11 * 8 + 1];

        const cx = (x00 + x10 + x01 + x11) / 4;
        const cy = (y00 + y10 + y01 + y11) / 4;

        // Strain-based coloring
        const s00 = getStrain(i00) / (spacing * 0.5);
        const s10 = getStrain(i10) / (spacing * 0.5);
        const s01 = getStrain(i01) / (spacing * 0.5);
        const s11 = getStrain(i11) / (spacing * 0.5);
        const strain = Math.min((s00 + s10 + s01 + s11) / 4, 3.0);

        // Height-based brightness
        const heightNorm = Math.max(0, Math.min(1, (y00 + y10 + y01 + y11) / (4 * H)));
        const heightBright = 0.25 + 0.55 * (1 - heightNorm);

        // Base color
        const rBase = Math.floor(18 + strain * 80);
        const gBase = Math.floor(28 + strain * 40);
        const bBase = Math.floor(48 + strain * 30);

        const r00 = Math.min(255, Math.floor(rBase * heightBright));
        const g00 = Math.min(255, Math.floor(gBase * heightBright));
        const b00 = Math.min(255, Math.floor(bBase * heightBright));

        const r11 = Math.min(255, Math.floor(rBase * heightBright * 0.7));
        const g11 = Math.min(255, Math.floor(gBase * heightBright * 0.7));
        const b11 = Math.min(255, Math.floor(bBase * heightBright * 0.7));

        const grad = ctx.createLinearGradient(cx, cy - 20, cx, cy + 20);
        grad.addColorStop(0, `rgba(${r00},${g00},${b00},0.35)`);
        grad.addColorStop(1, `rgba(${r11},${g11},${b11},0.18)`);

        ctx.beginPath();
        ctx.moveTo(x00, y00);
        ctx.lineTo(x10, y10);
        ctx.lineTo(x11, y11);
        ctx.lineTo(x01, y01);
        ctx.closePath();
        ctx.fillStyle = grad;
        ctx.fill();
      }
    }

    // Draw line mesh
    ctx.lineWidth = 0.7;
    ctx.lineCap = 'round';

    for (let ci = 0; ci < constraints.length; ci++) {
      const ref = constraints[ci];
      if (!ref) continue;
      const ai = ref[0];
      const bi = ref[1];

      const ax = points[ai * 8 + 0], ay = points[ai * 8 + 1];
      const bx = points[bi * 8 + 0], by = points[bi * 8 + 1];

      const dx = bx - ax, dy = by - ay;
      const dist = Math.sqrt(dx * dx + dy * dy);
      const strain = Math.min(dist / (ref[2] * 0.4), 3.0);

      const r = Math.min(255, 80 + strain * 140);
      const g = Math.min(255, 100 + strain * 60);
      const b = Math.min(255, 140 + strain * 30);

      ctx.beginPath();
      ctx.moveTo(ax, ay);
      ctx.lineTo(bx, by);
      ctx.strokeStyle = `rgb(${r|0},${g|0},${b|0})`;
      ctx.stroke();
    }

    // Draw pin points
    for (let c = 0; c < COLS; c++) {
      if (pinSet[c]) {
        const px = points[c * 8 + 0];
        const py = points[c * 8 + 1];
        ctx.beginPath();
        ctx.arc(px, py, 4, 0, Math.PI * 2);
        ctx.fillStyle = '#a0b0d0';
        ctx.fill();
        ctx.beginPath();
        ctx.arc(px, py, 2, 0, Math.PI * 2);
        ctx.fillStyle = '#d0e0ff';
        ctx.fill();
      }
    }
  }

  // ---- Mouse Interaction ----

  function findNearestPoint(mx, my) {
    let bestIdx = -1;
    let bestDist = MOUSE_RADIUS * MOUSE_RADIUS;
    for (let i = 0; i < COLS * ROWS; i++) {
      const dx = mx - points[i * 8 + 0];
      const dy = my - points[i * 8 + 1];
      const d = dx * dx + dy * dy;
      if (d < bestDist) {
        bestDist = d;
        bestIdx = i;
      }
    }
    return bestIdx;
  }

  function findNearestConstraint(mx, my) {
    let bestIdx = -1;
    let bestDist = CUTOFF_DIST * CUTOFF_DIST;
    for (let ci = 0; ci < constraints.length; ci++) {
      const ref = constraints[ci];
      if (!ref) continue;
      const ai = ref[0], bi = ref[1];
      const ax = points[ai * 8 + 0], ay = points[ai * 8 + 1];
      const bx = points[bi * 8 + 0], by = points[bi * 8 + 1];
      const dx = bx - ax, dy = by - ay;
      const lenSq = dx * dx + dy * dy;
      let t = ((mx - ax) * dx + (my - ay) * dy) / lenSq;
      t = Math.max(0, Math.min(1, t));
      const px = ax + t * dx, py = ay + t * dy;
      const ddx = mx - px, ddy = my - py;
      const d = ddx * ddx + ddy * ddy;
      if (d < bestDist) {
        bestDist = d;
        bestIdx = ci;
      }
    }
    return bestIdx;
  }

  canvas.addEventListener('mousedown', e => {
    e.preventDefault();
    const rect = canvas.getBoundingClientRect();
    mouse.x = e.clientX - rect.left;
    mouse.y = e.clientY - rect.top;
    mouse.down = true;
    mouse.right = e.button === 2 || e.shiftKey;
    mouse.px = mouse.x;
    mouse.py = mouse.y;

    if (!mouse.right) {
      const idx = findNearestPoint(mouse.x, mouse.y);
      if (idx >= 0 && !pinSet[idx]) {
        dragging = true;
        dragPoint = idx;
      }
    }
  });

  canvas.addEventListener('mousemove', e => {
    const rect = canvas.getBoundingClientRect();
    mouse.px = mouse.x;
    mouse.py = mouse.y;
    mouse.x = e.clientX - rect.left;
    mouse.y = e.clientY - rect.top;
  });

  canvas.addEventListener('mouseup', e => {
    mouse.down = false;
    mouse.right = false;
    dragging = false;
    dragPoint = null;
  });

  canvas.addEventListener('mouseleave', () => {
    mouse.down = false;
    mouse.right = false;
    dragging = false;
    dragPoint = null;
  });

  canvas.addEventListener('contextmenu', e => e.preventDefault());

  canvas.addEventListener('dblclick', e => {
    e.preventDefault();
    const rect = canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;
    const ci = findNearestConstraint(mx, my);
    if (ci >= 0) {
      constraints[ci] = null;
    }
  });

  // ---- Main Loop ----

  function loop(time) {
    requestAnimationFrame(loop);

    if (!lastTime) { lastTime = time; return; }
    let dt = (time - lastTime) / 1000;
    lastTime = time;
    dt = Math.min(dt, 1 / 20);
    frameCount++;

    // Handle right-click / shift-click cutting
    if (mouse.right && mouse.down) {
      const ci = findNearestConstraint(mouse.x, mouse.y);
      if (ci >= 0) {
        constraints[ci] = null;
      }
    }

    // Handle drag point
    if (dragging && dragPoint !== null && mouse.down && !mouse.right) {
      const idx = dragPoint;
      if (!pinSet[idx]) {
        const targetX = mouse.x;
        const targetY = mouse.y;
        points[idx * 8 + 0] = points[idx * 8 + 0] + (targetX - points[idx * 8 + 0]) * 0.4;
        points[idx * 8 + 1] = points[idx * 8 + 1] + (targetY - points[idx * 8 + 1]) * 0.4;
      }
    }

    simulate(dt);
    render();

    // NaN check every 60 frames
    if (frameCount % 60 === 0) {
      let ok = true;
      for (let i = 0; i < points.length; i++) {
        if (isNaN(points[i]) || !isFinite(points[i])) {
          ok = false;
          break;
        }
      }
      if (!ok) {
        console.warn('NaN detected, resetting simulation');
        initPoints();
        initConstraints();
      }
    }
  }

  window.addEventListener('resize', () => {
    init();
  });

  init();
  requestAnimationFrame(loop);
})();
</script>
